    ('SQL-G90', '221', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''50'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 > 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G90', '222', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 < 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)', NULL, NULL, NULL, NULL, NULL, NULL),
