    ('SQL-G90', '241', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) = ''99'' and TP <> '' )', NULL, NULL, NULL, NULL, NULL, NULL),
