    ('SQL-R08', '250', 'update TransX set Flex2 = m.Field1 + '' '' + m.Field2 from TransX t inner join Misc_Tables m on t.Hierarchy = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''DACanalysis'' and ID = ''Hierarchy', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '439', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1551', 'select ''1551'',x.TabName,x.RowNbr,''GL-Co'',x.HKONT + ''-'' + x.BUKRS,''GL only accepts "ZE" doc type for Co'',''DocType'',x.BLART from ParkerTrans0 x inner join sets s on s.ID = ''ZGL037'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal inner join sets t on t.ID = ''ZCO006'' and x.BUKRS >= t.FromVal and x.BUKRS <= t.ThruVal left join sets u on u.ID = ''ZDT007'' and x.BLART >= u.FromVal and x.BLART <= u.ThruVal where u.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1552', 'select ''1552'',x.TabName,x.RowNbr,''GL'',x.HKONT,''GL does not allow that PC'',''PCtr'',x.PRCTR from ParkerTrans0 x inner join sets s on s.ID = ''ZGL038'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal inner join sets t on t.ID = ''ZPC001'' and x.PRCTR >= t.FromVal and x.PRCTR <= t.ThruVal left join sets u on u.ID = ''ZLD001'' and x.LDGRP >= u.FromVal and x.LDGRP <= u.ThruVal where u.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G30', '211', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''3572002'' as GL, Crcy, PC, TP, ProdCode, 0 as Amt1, round(-Amt2,2) as Amt2, round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G30', '331', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)', NULL, NULL, NULL, NULL, NULL, NULL),
