    ('SQL-M25', '605', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, ''5600052'' as GL, '' as TTY, TP, BusCat, ''G23'' as SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''02 RI'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and Flex5 = ''10 WH/Other'' and GL = ''2880000'' and SubProd = ''G23'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '220', 'Update x set Amt1 = round(Amt1*c.Rate,2), Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Crcy and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '606', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, ''5600052'' as GL, '' as TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''05 Other'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and Flex5 = ''10 WH/Other'' and GL = ''2880000'' and SubProd = ''G23'')', NULL, NULL, NULL, NULL, NULL, NULL),
