    ('SQL-G26', '211', 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, x.GL + '' '' + TTY as Assgnmt, Crcy, m.Field5 as TTY, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID in (''[batchID]'',''[batchID]-data8''))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G25', '221', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC,ProdCode,PTF,Flex5)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '235', 'Update x set PC = ''7'' + m1.field2 + m2.field2 + (case when x.BusCat = ''20'' then ''A'' else ''C'' end) + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID in (''[batchID]'',''[batchID]-data8'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '314', 'Update t set Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.Field3 = ''convert'' and m.ID = ''Co'' and m.Descr = t.Co inner join CrcyRates r1 on r1.Crcy = m.Field2 and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = m.Field4 and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID in (''[batchID]'',''[batchID]-data8'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '221', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, Amt1, Amt2, Amt3,Zone) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3,Zone from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC,ProdCode,PTF,Assgnmt,Flex5,Zone)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '243', 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'')', NULL, NULL, NULL, NULL, NULL, NULL),
