    ('SQL-G32', '451', 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '452', 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')', NULL, NULL, NULL, NULL, NULL, NULL),
