    ('SQL-G28', '164', 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Flex3,Flex4,Flex1,Flex2,Location) (select ''[batchID]-data4'' as KeyID, Co,Crcy,GL,PC,CC,Amt1 * (Rate1 - Rate2) * Rate3,Amt2 * (Rate1 - Rate2) * Rate3,Amt3 * (Rate1 - Rate2) * Rate3,CCcat, ''Y'' as Deferrable_Flag, ''N'' as Attributable_Flag, Flex1, Flex2,Location from TransX where KeyID = ''[batchID]-data3'' and Rate1 > Rate2)', NULL, NULL, NULL, NULL, NULL, NULL),
