    ('SQL-M13', '412', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G49', '213', 'update TransX set Flex6 = ''30'', Amt1 = Amt3 from TransX where KeyID = ''[batchID]'' and Amt3 is not null', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R42', '300', 'update TransX set Flex5 = (case when Flex2 is NULL then ''no'' else ''yes'' end) from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R31', '201', 'insert into TransX (KeyID, Yr,Period,Co, GL, PC, UWYR, Amt1, Amt2, Flex1) (select KeyID, Yr, Period, Co, GL, PC, UWYR, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,Yr,Period,Co,GL,PC,UWYR)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R08', '203', 'update TransX set Flex3 = ''Income Statement'' from TransX where KeyID = ''[batchID]'' and GL >= ''4000000', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R74', '302', 'Update x set x.CCdesc = y.Descr from TransX x inner join CCtrs y on x.Contract = y.CCtr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '494', 'update TransX set Flex5 = 34 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and TP in (''2008'',''2201'') and (contract like ''CSIC ST%'' or Contract like ''GIC ST%'' or Contract like ''GICD ST%'' or Contract = ''HUD 2101'' or Contract = ''OPUS 2200'')', NULL, NULL, NULL, NULL, NULL, NULL),
