    ('SQL-M13', '413', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '414', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
