    ('SQL-R16', '301', 'insert into TransX (KeyID,Flex1,Flex2,Flex3,Flex5,ReinName,Flex6,Amt3,Amt4) select ''[batchID]'',x.Flex1,''prorate'',x.Flex3,''non-affiliate'',x.ReinName,x.Flex6,round(x.Amt3/z.Amt3*y.Amt3,2),round(x.Amt4/z.Amt4*y.Amt4,2) from (select Flex1,Flex3,ReinName,Flex6,round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex5 = ''non-affiliate'' and Flex6 <> '' group by Flex1,Flex3,ReinName,Flex6) x inner join (select Flex1,Flex3,Amt3,Amt4 from (select Flex1,Flex3,sum(Amt3) as Amt3,sum(Amt4) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex6 = '' group by Flex1, Flex3) a where Amt3 <> 0 or Amt4 <> 0) y on y.Flex1 = x.Flex1 and y.Flex3 = x.Flex3 inner join (select Flex1,Flex3,Amt3,Amt4 from (select Flex1,Flex3,sum(Amt3) as Amt3,sum(Amt4) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex5 = ''non-affiliate'' and Flex6 <> '' group by Flex1,Flex3) b where Amt3 <> 0 or Amt4 <> 0) z on z.Flex1 = x.Flex1 and z.Flex3 = x.Flex3', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16', '200', 'update TransX set ReinName = m.CEDANT_REINSURER_CODE from TransX t inner join [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] m on t.Co = m.LEGAL_ENTITY and t.Contract = m.CONTRACT_NO and t.UWYR = m.UW_YEAR where KeyID = ''[batchID]'' and not t.Contract in ('',''UNKNOWN'') and not ReinName in (select z.CEDANT_REINSURER_CODE from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] z where z.CONTRACT_NO = t.Contract and z.UW_YEAR = t.UWYR and z.LEGAL_ENTITY = t.Co)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-T03', '101', 'insert into TransX (KeyID,PC,Flex1,PCdesc,Hierarchy,Division,Region,Location,Zone,Flex6,Flex7,Flex8,Flex2,Flex3,Flex4,Flex5) (select ''[batchID]'',PCTR,Name,Descr,Hierarchy,Division,Region,Location,Zone,MajorClass,Product,Program,Blocked,ValidThru,UpdatedOn,UpdatedBy from PCTRS)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '413', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'' as KeyID, ''9999'' as Co, ''filler'' as GL, '' as Crcy, '' as PC, '' as TTY, '' as TP, '' as  Assgnmt, '' as ProdCode, '' as PTF, 0 as Amt1, 0 as  Amt2 , 0 as  Amt3)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '226', 'delete from TransX where KeyID = ''[batchID]-data2''  and ''[yyyy-mm-dd]'' = ''2022-01-31'' and (GL = ''1099917'' or GL > ''3000000'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '431', 'update TransX set TTY = '' from TransX where KeyID = ''[batchID]'' and GL in (''2853500'',''3870003'') and not ''[yyyy-mm-dd]'' = ''2022-01-31', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1216', 'Select ''1216'',x.TabName,x.RowNbr,''Rein Loc'',x.ZZREILOC,''Invalid code - not in table.'','','' from ParkerTrans0 x left join ReinLocs y on x.ZZREILOC = y.ReinLoc where x.ZZREILOC <> '' and y.ReinLoc is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '433', 'update TransX set ProdCode = ''U1892'', PTF = ''U3650'' from TransX where KeyID = ''[batchID]'' and GL = ''4600000'' and coalesce(ProdCode,'') = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G77', '404', 'update TransX set Amt2 = 0 where KeyID = ''[batchID]'' and PK = ''40'' and Amt2 < 0', NULL, NULL, NULL, NULL, NULL, NULL),
