    ('SQL-G77', '501', 'update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G77', '502', 'update TransX set Txt = ''Mexico-Newline Chargeback for [Yr]/[Mo]'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1217', 'Select ''1217'',x.TabName,x.RowNbr,''Cat Code'',x.ZZCATCOD,''Invalid code - not in table.'','','' from ParkerTrans0 x left join CatCodes y on replace(x.ZZCATCOD,'','') = y.CatCode where x.ZZCATCOD <> '' and y.CatCode is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1218', 'Select ''1218'',x.TabName,x.RowNbr,''PTF'',x.ZZPREMTR,''Invalid code - not in table.'','','' from ParkerTrans0 x left join PTFs y on x.ZZPREMTR = y.PTF where x.ZZPREMTR <> '' and y.PTF is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1219', 'Select ''1219'',x.TabName,x.RowNbr,''Broker'',x.ZZBROKER,''Invalid code - not in table.'','','' from ParkerTrans0 x left join Brokers y on x.ZZBROKER = y.Broker where x.ZZBROKER <> '' and y.Broker is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1220', 'Select ''1220'',x.TabName,x.RowNbr,''Sub Producer'',x.ZZSUBPRO,''Invalid code - not in table.'','','' from ParkerTrans0 x left join SubProds y on x.ZZSUBPRO = y.SubProd where x.ZZSUBPRO <> '' and y.SubProd is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1221', 'Select ''1221'',x.TabName,x.RowNbr,''Reinsurer'',x.ZZREINSN,''Invalid code - not in table.'','','' from ParkerTrans0 x left join Brokers y on x.ZZREINSN = y.Broker where x.ZZREINSN <> '' and y.Broker is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1222', 'Select ''1222'',x.TabName,x.RowNbr,''Risk Terr'',x.ZZRISKTER,''Invalid code - not in table.'','','' from ParkerTrans0 x left join ReinLocs y on x.ZZRISKTER = y.ReinLoc where x.ZZRISKTER <> '' and y.ReinLoc is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1223', 'Select ''1223'',x.TabName,x.RowNbr,''Status'',x.ZZSTATUS,''Invalid code - not in table.'','','' from ParkerTrans0 x left join StatusRSG y on x.ZZSTATUS = y.Stat where x.ZZSTATUS <> '' and y.Stat is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1224', 'Select ''1224'',x.TabName,x.RowNbr,''Trans Code'',x.ZZTRANCD,''Invalid code - not in table.'','','' from ParkerTrans0 x left join TransCodes y on x.ZZTRANCD = y.TransCode where x.ZZTRANCD <> '' and y.TransCode is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1225', 'Select ''1225'',x.TabName,x.RowNbr,''Order#'',x.AUFNR,''Invalid code - not in table.'','','' from ParkerTrans0 x left join Orders y on x.AUFNR = y.OrderNbr where x.AUFNR <> '' and y.OrderNbr is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S32', '302', 'delete from TransX where KeyID = ''[batchID]'' and GL < ''6000000'' and GL <> ''4498000'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G34', '221', 'insert into TransX (KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, Amt1, Amt2) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G34', '222', 'delete from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S32', '321', 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,PC,CC,BusCat,round(sum(Amt1),2) as Amt1, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,  PC, CC, BusCat)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1226', 'Select ''1226'',x.TabName,x.RowNbr,''Pymt Method'',x.ZLSCH,''Invalid code - not in table.'','','' from ParkerTrans0 x left join Misc_Tables y on x.ZLSCH = y.ID and y.Table_ID = ''PymtMethod'' where x.ZLSCH <> '' and y.ID is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '251', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''203%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G87', '402', 'insert into TransX (KeyID, Co,GL, Crcy,PC, CC, Contract, ProdCode,TP,Amt1, Amt2, Amt3,PK) (Select KeyID, Co,GL, Crcy,PC,CC, Contract, ProdCode,TP,(case when Amt1 < 0 then Amt1 else 0 end) as Amt1,(case when Amt2 < 0 then Amt2 else 0 end) as Amt2,  (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and (Amt1 < 0 or Amt2 < 0 or Amt3 < 0))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16f', '111', 'update TransX set Amt4 = Round(Amt1*r.rate/rc.rate,2) from TransX t inner join CrcyRates r on t.Crcy = r.Crcy inner join Companies c on t.Co = c.Co inner join CrcyRates rc on c.Crcy = rc.Crcy where KeyID = ''[batchID]'' and r.EffDate = ''[PY]-12-31'' and rc.EffDate = ''[PY]-12-31'' and r.Typ = ''S'' and rc.Typ = ''S''  and GL < ''2870000'' and not GL like ''%96'' and not GL like ''%98'' and not SUBSTRING(GL,1,4) in (''1320'') and not SUBSTRING(GL,1,3) in (''151'',''162'',''211'',''242'') and not t.PC in (''220CSIC000'',''221CSIC000'',''341CSIC000'') and Flex1 = ''pass2'' and not t.crcy = rc.crcy', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1227', 'Select ''1227'',x.TabName,x.RowNbr,''Pymt Term'',x.ZTERM,''Invalid code - not in table.'','','' from ParkerTrans0 x left join PymtTerms y on x.ZTERM = y.PymtTerm where x.ZTERM <> '' and y.PymtTerm is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G29', '513', 'update TransX set ProdCode = '' where KeyID = ''[batchID]'' and ProdCode is null', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '421', 'update TransX set Flex5 = 6 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and TP in (''2300'',''2400'',''2450'',''2008'') and substring(PC,1,1) =''6'' and not (substring(Contract,1,7) = ''FIRV ST'' or substring(Contract,1,3) =  ''FV-'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '198', 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''401'' + substring(GL,4,4) as GL, Assgnmt, Crcy, '' as TTY, TP, BusCat, PC, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''7'' and GL like ''131%'' and TTY = ''809'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G29', '301', 'insert into TransX (KeyID,Co,Yr,Period,GL,Ledger,Division,Region,Location,Zone,PCdesc,TPname,CCdesc,Crcy,PK,Amt1,Amt2,Amt3,Amt4,Amt5,RefKey1,RefKey2,RefKey3,Assgnmt,Txt,PC,CC,BusCat,TTY,UWYR,Broker,TP,PTF,Contract,ProdCode,BusCatDesc,ExpNode,Flex1,FSitem,RiskTerr,ReinLoc,CatCode,AccYr,ReinName,SubProd,TransCode,Stat) (select ''[batchID]-data2'',Co,Yr,Period,GL,Ledger,Division,Region,Location,Zone,PCdesc,TPname,CCdesc,Crcy,PK,Amt1,Amt2,Amt3,Amt4,Amt5,RefKey1,RefKey2,RefKey3,Assgnmt,Txt,PC,CC,BusCat,TTY,UWYR,Broker,TP,PTF,Contract,ProdCode,BusCatDesc,ExpNode,Flex1,FSitem,RiskTerr,ReinLoc,CatCode,AccYr,ReinName,SubProd,TransCode,Stat from TransX where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G29', '462', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' then '' else x.TTY end) and m.Field6 = ''1'' where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R27', '201', 'insert into TransX (KeyID, Ledger,GL,Co, TP, TTY, Amt1, Amt2, Flex3) (select KeyID, Ledger,GL,Co, TP, TTY, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, ''pass1'' as Flex3 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger,GL,Co, TP, TTY)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R27', '202', 'delete from TransX where KeyID = ''[batchID]'' and (Flex3 is NULL or (Amt1 = 0 and Amt2 = 0))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R27', '211', 'update TransX set Flex1 = ''Gross Unpaid Claim Liabilities'' from TransX where KeyID = ''[batchID]''  and GL like ''20%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R27', '212', 'update TransX set Flex1 = ''Ceded Unpaid Claim Liabilities'' from TransX where KeyID = ''[batchID]''  and GL like ''14%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16c', '122', 'delete from TransX where KeyID = ''[batchID]'' and Amt2 = 0 and Amt3 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16c', '149', 'update TransX set Amt4 = NULL, Flex1 = ''pass1'' from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16', '223', 'update TransX set TPname = m.Name from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R03', '203', 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E00', '1105', 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]-save'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E00', '1110', 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E00', '1115', 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]-save'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E12', '2001', 'update TransX set CC = ''5EOI000000'', PC = '' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and CostCenter = 1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G88', '401', 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, (case when Amt4 > 0 then Amt4 else 0 end) as Amt4, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G88', '402', 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, (case when Amt4 < 0 then Amt4 else 0 end) as Amt4, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S03', '512', 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R18', '131', 'update TransX set Amt3 = Amt1 - Amt2, Amt5 = Amt1 - Amt4, Amt7 = Amt1 - Amt6 where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G88', '403', 'delete from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R18', '132', 'delete from TransX where KeyID = ''[batchID]'' and (Flex6 is null or (Amt1 = 0 and Amt2 = 0 and Amt4 = 0 and Amt6 = 0))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R18', '133', 'update TransX set Flex1 = Mapkey from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL where keyID = ''[batchID]'' and mapkey like ''M1-2-7-%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R18', '134', 'update TransX set Flex2 = m.Name from TransX t inner join mapkeys m on t.flex1 = m.mapkey where keyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R18', '135', 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is null', NULL, NULL, NULL, NULL, NULL, NULL),
