    ('SQL-G87', '211', 'insert into TransX (KeyID, Co,GL, Crcy,CC, Contract, ProdCode, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, CC, Contract, ProdCode, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3, '' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, CC, Contract, ProdCode)', NULL, NULL, NULL, NULL, NULL, NULL),
