    ('SQL-R63', '202', 'insert into TransX (KeyID, Qtr, Co, GL, PC, CCcat, TP, BusCat, TTY, Amt1, Amt2, Amt3, Amt4) (select KeyID, 0 as Qtr, Co, GL, PC, CCcat, TP, BusCat, TTY, round(sum(Amt3),2) as Amt1, round(sum(Amt1-Amt2),2) as Amt2, round(sum(Amt1-Amt3),2) as Amt3, round(sum(Amt1),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Qtr = 2 group by KeyID, Co, GL, PC, CCcat, TP, BusCat, TTY)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R63', '203', 'delete from TransX where KeyID = ''[batchID]'' and Qtr = 2', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R63', '211', 'insert into TransX (KeyID, Qtr, Co, GL, PC, CCcat, TP, BusCat, TTY, TransCode, PTF, ProdCode, Amt1, Amt2, Amt3, Amt4) (select KeyID, 4 as Qtr, Co, GL, PC, CCcat, TP, BusCat, TTY, TransCode, PTF, ProdCode, round(sum(Amt3),2) as Amt1, round(sum(Amt1-Amt2),2) as Amt2, round(sum(Amt1-Amt3),2) as Amt3, round(sum(Amt1),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Qtr = 1 group by KeyID, Co, GL, PC, CCcat, TP, BusCat, TTY, TransCode, PTF, ProdCode)', NULL, NULL, NULL, NULL, NULL, NULL),
