    ('SQL-R63', '301', 'insert into TransX (KeyID, Co, GL, PC, TP, BusCat, Amt1, Amt2, Amt3, Amt4) (select ''[batchID]-data2'', Co, GL, PC, TP, BusCat, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Qtr = 0 and GL >= ''5410000'' and GL <= ''5599999'' group by Co, GL, PC, TP, BusCat)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R63', '302', 'insert into TransX (KeyID, Co, GL, PC, TP, BusCat, Amt1, Amt2, Amt3, Amt4) (select ''[batchID]-data2'', Co, GL, PC, TP, BusCat, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Qtr = 0 and GL like ''982%'' group by Co, GL, PC, TP, BusCat)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R63', '303', 'update TransX set Division = p.Division,  Region = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR where KeyID = ''[batchID]-data2', NULL, NULL, NULL, NULL, NULL, NULL),
