    ('SQL-R15', '211', 'update TransX set Flex1 = ''Ceded'', Flex2 = ''no'', Flex5 = ''non-affiliate'', Amt2 = Amt1 from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '212', 'update TransX set Flex1 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and BusCat >= ''20'' and BusCat <= ''29', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '214', 'update TransX set Flex1 = ''Direct'' from TransX where KeyID = ''[batchID]'' and BusCat = ''10', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '215', 'update TransX set Flex2 = ''yes'' from TransX where KeyID = ''[batchID]'' and (GL like ''%96'' or GL like ''%98'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '216', 'update TransX set Flex3 = m.Descr from TransX t inner join Misc_Tables m on substring(t.GL,1,3) = m.ID and t.Flex1 = m.Field1 where KeyID = ''[batchID]'' and m.Table_ID = ''GL Sched F', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '218', 'update TransX set Amt2 = -Amt1 from TransX where KeyID = ''[batchID]'' and ((substring(GL,1,1) = ''4'' and Flex1 <> ''Ceded'') or (substring(GL,1,1) = ''5'' and Flex1 = ''Ceded''))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R15', '220', 'update TransX set TP = Field1 from TransX inner join Misc_Tables on ReinName = Descr where  KeyID = ''[batchID]'' and Table_ID = ''TP Sched F'' and TP is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '221', 'insert into TransX (KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, Amt1, Amt2) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TP, PC,ProdCode,PTF)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '222', 'delete from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '223', 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '231', 'insert into TransX (KeyID, GL, PC, Amt2, Flex1) (Select ''[batchID]'' as KeyID, substring(GL,3,1), substring(PC,1,6), round(sum(Amt2),2) as Amt2, ''pass1'' from TransX where KeyID = ''[batchID]-data2'' group by substring(GL,3,1),substring(PC,1,6))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '232', 'update TransX set Amt2 = 1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''6', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '233', 'update TransX set Amt2 = -1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''5', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '234', 'update TransX set GLdesc = (case when Amt2 >= 0 then 150 else 210 end) + GL where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '241', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2,Assgnmt) (Select y.KeyID, x.Co, y.GLdesc + substring(x.GL,4,4), x.Crcy, ''877'' as TTY, x.TP, x.PC, x.ProdCode, x.PTF, x.Amt1, x.Amt2,x.GL from TransX x inner join TransX y on substring(x.PC,1,6) = y.PC and substring(x.GL,3,1) = y.GL and x.KeyID = ''[batchID]-data2'' and y.KeyID = ''[batchID]'' where substring(x.GL,1,3) <> y.GLdesc)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '242', 'delete from TransX where KeyID = ''[batchID]'' and Crcy is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '243', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2,Assgnmt) (Select KeyID, Co, Assgnmt, Crcy, TTY, TP, PC, ProdCode, PTF, round(-Amt1,2), round(-Amt2,2),Assgnmt from TransX where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '331', 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G33', '332', 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)', NULL, NULL, NULL, NULL, NULL, NULL),
