    ('SQL-P00', '1036', 'update x set GL = m.Descr from TransX x inner join Misc_Tables m on x.GL = m.ID and m.Table_ID = ''ElimGLmap3'' and m.field1 = ''CtoA'' inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and substring(x.GL,6,2) in (''96'',''98'') and e.TrueUpAorC = ''A'' and not e.TrueUpCo in (''2201'',''2300'',''2400'',''2450'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-P00', '1037', 'update x set GL = ''441'' + substring(x.GL,4,4) from TransX x  inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and x.GL like ''682%'' and e.TrueUpAorC = ''A', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-P00', '1038', 'update x set GL = ''682'' + substring(x.GL,4,4) from TransX x  inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and x.GL like ''441%'' and e.TrueUpAorC = ''C', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-P00', '1040', 'update x set Contract = e.TrueUpContract from TransX  x inner join Eliminations e on e.ID = ''[ElimID]'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '104', 'insert into TransX (KeyID, Flex9, Co, GL, FSitem, TTY, TP, BusCat, SubProd, Amt1, Flex5) (Select KeyID, Flex9, Co, GL, FSitem, TTY, TP, BusCat, SubProd, Amt2, '' as Flex5 from TransX where KeyID = ''[batchID]'' and Co <> ''JE'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M42', '301', 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.Flex2 + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M42', '321', 'insert into TransX (KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,Amt1,Amt2) (select KeyID + ''-data2'', Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,ROUND(SUM(Amt1),2),ROUND(SUM(Amt2),2) from TransX where KeyID = ''[batchID]'' group by KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G43', '242', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1<0 then Amt1 else 0 end as Amt1, case when Amt2<0 then Amt2 else 0 end as Amt2,  case when Amt3<0 then Amt3 else 0 end as Amt3,  ''50'' as PK from TransX where KeyID = ''[batchID]'' )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R82', '232', 'insert into TransX (KeyID,Flex1,Crcy,Flex2,Flex3,Date1,Period,Rate1,Flex4,Amt2,Amt3,Flex5,Flex6,Flex7) (select ''[batchID]'',''01'',r.Crcy,''USD'',''Y'',''[yyyy-mm-dd]'',0,round(avg(round(1/r.rate/c.xfactor,5)),5) as rate,'',c.xfactor,1,'','','' from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy,c.xfactor)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S20', '321', 'update TransX set PC = '', CC = c.CCtr From TransX x inner join (Select Co,PCtr,max(CCtr) as CCtr from CCtrs group by Co,Pctr) c on x.Co = c.Co and x.PC = c.PCtr where KeyID = ''[batchID]'' and x.Co < ''5001'' and x.GL > ''6000000'' and x.GL < ''7100000', NULL, NULL, NULL, NULL, NULL, NULL),
