    ('SQL-P00', '1081', 'insert into TransX (KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3) (Select x.KeyID, x.Ledger, x.Crcy, x.Co, y.Descr as GL, x.PC, x.Contract, x.TP, x.BusCat, y.Field2 as TTY, round(x.Amt1 * y.Field3,2) as Amt1, round(x.Amt3 * y.Field3,2) as Amt3 from TransX x inner join Misc_Tables y on x.GL = y.ID and (substring(x.BusCat,1,1) = substring(y.Field1,1,1) or (substring(x.BusCat,1,1) = '' and substring(y.Field1,1,1) = ''3''))and y.Table_ID in (''ElimGLmap7'',''ElimGLmap8'') where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
