    ('SQL-M13', '417', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data8'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other where source = ''R69'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control where source = ''R63'' and GL in (''nothing'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1215', 'Select ''1215'',x.TabName,x.RowNbr,''BusCat'',x.ZZREINTY,''Invalid code - not in table.'','','' from ParkerTrans0 x left join Misc_Tables y on x.ZZREINTY = y.ID and y.Table_ID = ''BusCat'' where x.ZZREINTY <> '' and y.ID is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
