    ('SQL-T14', '101', 'insert into TransX (KeyID,Flex1,Flex2,Crcy,Flex3,Rate1,Yr,Period,Flex5,Flex6) (select ''[batchID]'',EffDate,Typ,r.Crcy,Name,Rate,xfactor,DecimalPlaces,RSG,Notes from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where EffDate >= ''[FROMyyyy-mm-dd]'' and EffDate <= ''[THRUyyyy-mm-dd]'' and Typ like ''[version]'' and r.Crcy like ''[GL]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '103', 'Update TransX set Crcy = ''RSD'' where KeyID = ''[batchID]'' and Crcy = ''CSD', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '111', 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and BusCat like ''3%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '112', 'Update TransX set BusCat = ''D'' where KeyID = ''[batchID]'' and BusCat = ''10', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '113', 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and BusCat like ''2%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '114', 'Update TransX set BusCat = (case when substring(GL,1,2) in (''13'') then ''A'' else ''C'' end) where KeyID = ''[batchID]'' and (BusCat = '' or BusCat = ''XX'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M11', '201', 'Update TransX set Flex1 = ''I'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '571', 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'') and Flex9 = ''translate', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M31', '131', 'delete from SAP_ledger_data_temp where fiscal_year = [Yr] and not coalesce(flex1,'') = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M31', '141', 'update SAP_ledger_data_temp set doc_amt = -doc_amt, lc_amt = -lc_amt, lc2_amt = -lc2_amt, gl_doc_amt = -gl_doc_amt where Flex1 = ''[batchID]'' and Flex2 = ''H', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '224', 'update TransX set Flex1 = ''OC'' from TransX where KeyID = ''[batchID]'' and (substring(PC,1,2) = ''16'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '261', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3,Assgnmt) (Select ''[batchID]-data3'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, (case when Co like ''9%'' then '' else ''x'' + Flex1 + ''x'' + Flex2 + ''x'' + Flex3 end) as Assgnmt from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Flex1, Flex2, Flex3)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '315', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, m.Field1 as Co, t.GL, t.Crcy, t.PC,t.TTY, t.TP, t.BusCat, coalesce(t.Assgnmt,''), t.ProdCode, t.Amt1, t.Amt2 , t.Amt3 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Co9'' and m.Descr = t.Co where t.KeyID = ''[batchID]-data3'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G75', '454', 'update TransX set GL = ''6314000'' where KeyID = ''[batchID]'' and Co = ''3030'' and GL in (''6314005'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '582', 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '') where t.KeyID = ''[batchID]'' and not GL in (''4419900'') and Assgnmt is NULL and Flex9 = ''translate', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '583', 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL like m.Descr and (BusCat = m.Field6 or m.Field6 = '') where t.KeyID = ''[batchID]'' and not GL in (''4419900'') and Assgnmt is NULL and Flex9 = ''translate', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '434', 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and Co in (''2999'',''3999'') and SubProd= ''G23'' and Flex5 = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '435', 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and TP = ''ODY'' and SubProd= ''G23'' and Flex5 = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '291', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''806'' as TTY, TP, BusCat, coalesce(Assgnmt,''), ''U1801'' as ProdCode, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '292', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''803'' as TTY, TP, BusCat, coalesce(Assgnmt,''), ''U1801'' as ProdCode, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G31', '321', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '212', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, x.GL + '' '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'',''232'') then '' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '190', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'', Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Amt1, Amt2, Amt3 from Trans3 where KeyID = ''LS-SING-data3'' and substring(''[BudAct]'',1,7) = ''LS-SING'' and ''[yyyy-mm-dd]'' like ''2022%'' and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and not ''[version]'' = ''First'' )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S43', '535', 'Update t set t.YearPeriod = s.fiscal_year + s.period , t.Yr = s.fiscal_year , t.Period = s.period , t.Co = s.co , t.Crcy = s.crcy , t.PC = s.profit_centre , t.CC = s.cost_centre , t.TP = s.trade_ptr , t.BusCat = s.bus_cat , t.Contract = coalesce(s.contract, '') , t.UWYR = s.uwyr , t.TTY = s.trans_type from TransX t join CorpAcct_Apps.dbo.SAP_ledger_data s on t.GL = s.gl and t.Amt1 = s.doc_amt where KeyID = ''[batchID]'' and (t.Contract is null or t.Contract = '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G80', '361', 'insert into TransX (KeyID, GL, Amt1, Amt2, Amt3,CC,PC,TP,Contract,ProdCode,PK) (Select KeyID, ''1998900'' as GL, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2,  round(-sum(Amt3),2) as Amt3,'' as CC,''1600000000'' as PC, ''F0085'' as TP,''1CBA000006'' as Contract,'' as ProdCode, ''99'' as PK from TransX where KeyID = ''[batchID]'' and ProdCode = ''CHGBACK'' group by KeyID)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E24', '1066', 'update TransX set PC = ''3992080000'' where KeyID = ''[batchID]'' and Co = ''3999'' and Contract = ''QS', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S01', '509', 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 in (''pass2'',''pass3'') or Amt1 = 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S01', '513', 'update TransX set Ledger = ''Z000'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Amt1 = Amt3 and Amt1 = Amt4', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S01', '514', 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Amt1 = Amt2 and Amt1 = Amt4', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '484', 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co in (''2300'',''2400'',''2450'')  and not Contract like ''FV-%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '485', 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and (TP = ''2008'' or (TP in (''2300'',''2400'',''2450'') ) and tp <> ''2310'') and (PC in (''1002000000'',''5380000000'',''1000000000'',''1426720828'') or PC like ''140%'' or PC like ''4%'') and not Contract in (''CSIC 2008'',''GIC 2008'',''HUD 2101'',''HUD 2102'',''2300-2101'',''CSIC SC 2200'',''CB HIC 2006'',''GIC SC 2200'') and  not substring(Contract,1,7) in (''CSIC ST'' ,''CAD HIC'',''GICD ST'',''ST SYND'',''PSI HIC'',''HCN CAD'',''ORESA S'',''HCN CAF'') and not Contract like ''OPUS%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '486', 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and tp <> ''2310'' and upper(substring(Contract,1,5)) = ''HUD ST', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '487', 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and tp <> ''2310'' and substring(PC,1,1) = ''4'' and Contract = ''PC RECLASS', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '624', 'update TransX set Flex5 = ''100'', Flex6 = ''clearing ITD balance in current year'' where KeyID = ''[batchID]'' and Amt2 = 0 and Flex5 is NULL and upper(substring(contract,1,7)) not in (''FV-EUCL'',''HCN CAF'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '652', 'update TransX set Flex5 = ''138'', Flex6 = ''need to investigate small non-2999 FX balances and clear'' where KeyID = ''[batchID]'' and not Co = ''2999'' and Flex1 like ''9%'' and upper(substring(contract,1,7)) not in (''FV-EUCL'',''HCN CAF'') and Flex5 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '211', 'insert into TransX (KeyID, Co, GL, BusCat, PC,Amt1,Amt2,Amt3,Amt4,Amt7,Amt8,Flex1) (select KeyID, Co, GL, BusCat, PC, round(sum(coalesce(Amt1,0)),2), round(sum(coalesce(Amt1+Amt2,0)),2), round(sum(coalesce(Amt3,0)),2), round(sum(coalesce(Amt4,0)),2),round(sum(coalesce(Amt7,0)),2), round(sum(coalesce(Amt8,0)),2),''pass1'' from TransX where KeyID = ''[batchID]''  group by KeyID, Co, GL, BusCat, PC)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '411', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC2_Amt from (select Co,GL,PC,ACD, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC2_Amt) > 1 and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '420', 'update TransX set Flex1 = ''20 ORESA Paris'' from TransX where KeyID = ''[batchID]'' and Co = ''2999'' and TP in (''2002'',''4110'') and Contract like ''ORESA P%'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '424', 'update TransX set Flex1 = ''24 NEVAG QS'' from TransX where KeyID = ''[batchID]'' and Co in (''3070'',''3999'') and TP = ''3270'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '424', 'update TransX set Flex1 = ''24 NEVAG QS'' from TransX where KeyID = ''[batchID]'' and Co in (''3270'',''3999'') and TP = ''3070'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '425', 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''2200'' and TP = ''4110'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '425', 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''4110'' and TP = ''2200'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '425', 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''2999'' and TP in (''2200'',''4110'') and Contract like ''ORESA G%'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G24', '452', 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G24', '321', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, coalesce(PTF,''), Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, coalesce(PTF,''), Assgnmt)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S06', '510', 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S06', '511', 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-S06', '512', 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'') = isnull(f2.CC,'') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'') = isnull(f2.UWYR,'') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M16', '212', 'delete from TransX where KeyID = ''[batchID]''  and Flex4 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('OutSelect', 'W12a', 'CONTRACT', 'c', NULL, NULL, NULL, NULL, NULL),
    ('SQL-G25', '421', 'Update TransX set ProdCode =  ''U1806'' where KeyID = ''[batchID]'' and Co like ''599%'' and GL = ''1560000', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQLselect', 'W12a', 'insert into TransX (KeyID, YearPeriod, Co, GL, Contract, UWYR, Crcy, PC, BusCat, TP, Amt1) values (''[batchID]'',''[Yr][Mo]'',', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '901', 'insert into TransX (KeyID,YearPeriod,FSitemDesc,GLdesc,Period,Date1,Flex1,Qtr,Date2,Flex2,Yr,Flex3) (select ''[batchID]-data3'',e.ID, e.ShortName, e.Def, max(p1.VerNbr), max(p1.Finished), substring(max(right(''00''+convert(varchar,p1.VerNbr),2) + p1.RunBy),3,99), max(p2.VerNbr), max(p2.Finished), substring(max(right(''00''+convert(varchar,p2.VerNbr),2) + p2.RunBy),3,99), max(coalesce(p4.VerNbr,0)), max(p3.Comments) from Eliminations e left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Recon'') p1 on p1.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Elim'' and len(ID) < 3) p2 on p2.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Comments'') p3 on p3.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Elim'' and Comments = ''y'') p4 on p4.ID = e.ID where right(''000''+convert(varchar,e.ID),3) < ''050'' group by e.ID, e.ShortName, e.Def)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('FieldSelect', 'W12b', 'COCODE', 'a', NULL, NULL, NULL, NULL, NULL),
    ('FieldSelect', 'W12b', 'GL', 'b', NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '457', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data8'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other_Singapore where source = ''R69'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control_Singapore where source = ''R63'' and GL in (''nothing'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R49', '619', 'update TransX set Flex5 = ''Sched F'', Flex6 = ''Adj for Sched F (OK)'' from TransX where KeyID = ''[batchID]'' and Flex5 is Null and Contract = ''SCHED F', NULL, NULL, NULL, NULL, NULL, NULL),
