    ('SQL-T06', '101', 'insert into TransX (KeyID,Co,GL,GLdesc,Flex1,FSitem,FSitemDesc,Crcy,PC,Flex2,Flex3,Flex4,Flex5,Flex6) (Select ''[batchID]'',Co,x.GL, Name, c.Descr,F.FSitem, FSitemDesc,x.Crcy,FSG, Case when x.Blocked = ''No'' then c.Blocked else x.Blocked End as Blocked, BSorPL, Grp, x.CreatedBy, convert(varchar,x.CreatedOn,101) as CreatedOn from COAxCo x left join FSitems F on x.GL >= FromGL and x.GL <= ThruGL inner join COA c on c.GL = x.GL inner join Misc_Tables m on Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') inner join ElimSelect e on ElimID = ''Co:'' + m.ID where (e.Oper = ''EQ'' and x.Co = e.FromVal) or (e.Oper = ''BT'' and x.Co >= e.FromVal and x.Co <= e.ThruVal))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M17', '544', 'update TransX set Flex4 = Flex4 + ''LRC Ceded'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''156'',''216'') and GL like ''%00', NULL, NULL, NULL, NULL, NULL, NULL),
