    ('SQL-M17', '613', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '' as PC, ''G23-Rev'' as Txt, Amt1, FSitem, Flex1, Flex2, Flex3, replace(replace(Flex4,''01 '',''02 ''),''(Alex Start)'',''clear'') as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020100070'' and GL in (''1480000'',''2820000'') and not Flex4 like ''%clear'') a )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M17', '614', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '' as PC, ''G23-Rev'' as Txt, -Amt1, FSitem, Flex1, Flex2, Flex3, replace(replace(Flex4,''01 '',''02 ''),''(Alex Start)'',''clear (Alex ADJ)'') as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020100070'' and GL in (''1480000'',''2820000'') and not Flex4 like ''% clear'') a )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M17', '615', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '' as PC, ''G23-Rev'' as Txt, Amt1, FSitem, Flex1, Flex2, Flex3, ''02 '' + substring(Flex4,4,99) + '' clear (Alex ADJ)'' as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020200070'' and not GL in (''1480000'',''2820000'')) a )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M17', '616', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '' as PC, ''G23-Rev'' as Txt, -Amt1, FSitem, Flex1, Flex2, Flex3, ''02 '' + substring(Flex4,4,99) + '' clear'' as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020200070'' and not GL in (''1480000'',''2820000'')) a )', NULL, NULL, NULL, NULL, NULL, NULL),
