    ('SQL-G99', '241', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1>0 then Amt1 else 0 end as Amt1, case when Amt2>0 then Amt2 else 0 end as Amt2,  case when Amt3>0 then Amt3 else 0 end as Amt3,  ''40'' as PK from TransX where KeyID = ''[batchID]'' )', NULL, NULL, NULL, NULL, NULL, NULL),
