    ('SQL-S20', '301', 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,TTY,UWYR,Contract,ReinName,Amt1,Amt2,Amt3,Amt4,Txt,Assgnmt,RefKey1,RefKey2,PK,Flex3) (select ''[batchID]'' as KeyID,Ledger,Co,Crcy,RefKey1 as GL,PC,TP,BusCat,(case when substring(''[GL]'',3,2) = ''30'' then ''S20 FB'' else ''S20 FA'' end) as SubProd,(case when substring(''[GL]'',3,2) = ''30'' then ''990'' else ''991'' end) as TTY,UWYR,Contract,ReinName,0 as Amt1,(case when substring(''[GL]'',3,2) = ''10'' then Amt4 else 0 end) as Amt2,(case when substring(''[GL]'',3,2) = ''10'' then Amt5 else (case when substring(''[GL]'',3,2) = ''30'' then Amt4 else 0 end) end) as Amt3,(case when substring(''[GL]'',3,2) = ''60'' then Amt4 else 0 end) as Amt4,Txt,Assgnmt,RefKey1,RefKey2, (case when Amt4 > 0 then ''40'' else ''50'' end) as PK, ''FX calc [Yr]-[Mo]'' as Flex3 from TransX where KeyID = ''[batchID]-data2'')', NULL, NULL, NULL, NULL, NULL, NULL),
