    ('SQL-G75', '211', 'insert into TransX (KeyID, GL, Crcy,CC,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, GL, Crcy, CC, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, '' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL, Crcy,CC)', NULL, NULL, NULL, NULL, NULL, NULL),
