    ('SQL-G25', '112', 'update TransX set Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]''  and (''[yyyy-mm-dd]'' <> ''2022-01-31''  or Co like ''599%'')', NULL, NULL, NULL, NULL, NULL, NULL),
