    ('SQL-R82', '202', 'insert into TransX (KeyID,Flex1,Crcy,Flex2,Flex3,Date1,Period,Rate1,Flex4,Amt2,Amt3,Flex5,Flex6,Flex7) (select ''[batchID]'',''01'',r.Crcy,''USD'',''MAVG'',''[yyyy-mm-dd]'',0,round(avg(round(1/r.rate/c.xfactor,5)),5) as rate,'',c.xfactor,1,'','','' from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and month(r.EffDate) = ''[Mo]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy,c.xfactor)', NULL, NULL, NULL, NULL, NULL, NULL),
