    ('SQL-R82', '402', 'insert into CrcyRates (Typ,EffDate,Crcy,Rate) (select ''MAVG'',''[yyyy-mm-dd]'',r.Crcy,1/round(avg(round(1/r.rate,5)),5) from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and month(r.EffDate) = ''[Mo]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R82', '403', 'insert into CrcyRates (Typ,EffDate,Crcy,Rate) (select ''MAVG'',''[yyyy-mm-dd]'',Crcy,avg(rate) from CrcyRates where Typ = ''M'' and year(EffDate) = ''[Yr]'' and month(EffDate) = ''[Mo]'' and not Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by Crcy)', NULL, NULL, NULL, NULL, NULL, NULL),
