    ('SQL-M25', '413', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''07 Payables'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and substring(GL,1,3) in (''221'') and Flex9 = ''4'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '243', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1,''4398099'' as GL,''UGLOE FX'' as GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''4398%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 inner join (Select Crcy,PC,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''4398%'' and Flex1 = ''FX'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '244', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1,''4398099'' as GL,''UGLOE FX'' as GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''4398%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 left join (Select Crcy,PC,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL = ''4398099'' and UWYR = ''AW'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '245', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL > ''4000000'' and not GL like ''4398%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL > ''4000000'' and not GL like ''4398%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '246', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL > ''4000000'' and not GL like ''4398%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL > ''4000000'' and not GL like ''4398%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '247', 'delete from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and (GL > ''4000000'' or GL like ''359%'') and Flex1 = ''FX'' and not UWYR in (''AW'',''NoB'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '248', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''142%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''202%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '249', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''142%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''142%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '250', 'delete from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''142%'' and Flex1 = ''FX'' and not UWYR in (''AW'',''NoB'')', NULL, NULL, NULL, NULL, NULL, NULL),
