    ('SQL-R33', '206', 'insert into TransX (KeyID, Co, GL, Amt1, Amt2, Amt3, Amt4, Amt5, Flex1) (select KeyID, Co, GL, Amt1, Amt2, Amt3, Amt4, Amt5, ''M2-3-6-06-04-01'' as Flex1 from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and MapKey = ''M2-3-6-06-04-01'' )', NULL, NULL, NULL, NULL, NULL, NULL),
