    ('SQL-R25', '241', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1,''3590099'' as GL,''CTA FX'' as GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''359%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 inner join (Select Crcy,PC,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''359%'' and Flex1 = ''FX'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '242', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1,''3590099'' as GL,''CTA FX'' as GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''359%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 left join (Select Crcy,PC,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL = ''3590099'' and UWYR = ''AW'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
