    ('SQL-R83', '504', 'insert into Misc_Tables (Table_ID,ID,Descr,Field1,Field2,Field3) (select ''R83 Comm Pct'',Flex1,Co,cast(Amt3 as varchar),''calc'',Flex4 from TransX where KeyID = ''[batchID]-data2'' and Flex2 = ''calc'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M19', '231', 'update TransX set Flex1 = substring(PC,1,6), Flex2 = (case when substring(PC,6,1) = ''C'' then ''Port Reins/Ceded'' else ''Port Ins/Gross'' end), Flex3 = (case when substring(GL,3,1) = ''5'' then ''GL Ins/Gross'' else ''GL Reins/Ceded'' end), Flex4 = (case when substring(GL,1,1) = ''1'' then ''Asset'' else ''Liab'' end) where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G26', '252', 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '') where t.KeyID in (''[batchID]'',''[batchID]-data8'') and not GL in (''4419900'') and Assgnmt is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R83', '502', 'update TransX set Amt3 = (Case when Amt1 = 0 then 0 else round(Amt2*100/Amt1,2) end) where KeyID = ''[batchID]-data2', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G81', '191', 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,UWYR,Amt1,Amt2,Amt3,Amt4,Flex3) (select KeyID,Ledger,Co,Crcy,GL,PC,UWYR,(case when Flex3 = ''00'' then Amt1 else 0 end),(case when Flex3 = ''10'' then Amt1 else 0 end),(case when Flex3 = ''30'' then Amt1 else 0 end),(case when Flex3 = ''60'' then Amt1 else 0 end),''pass1'' from TransX where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '202', 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '211', 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '207', 'insert into TransX (KeyID, Yr, Crcy, Co, GL, TP, PC, BusCat, Contract, UWYR, Amt1, Amt2, Flex1) (select KeyID, Yr, Crcy, Co, replace(GL,''89'',''00'') as GL, TP, PC, BusCat, Contract, UWYR, Amt1, Amt2, Flex1 from TransX where KeyID = ''[batchID]'' and TTY = ''824'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('OutSelect', 'W11a', 'TRADINGPARTNER', 'g', NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '252', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '254', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '' as BusCat, '' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''219%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '255', 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '271', 'update TransX set UWYR = ''NoB'' from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and not UWYR = ''AW'' and Flex1 = ''FX', NULL, NULL, NULL, NULL, NULL, NULL),
