    ('SQLselect', 'W11a', 'insert into TransX (KeyID, YearPeriod, Co, GL, Crcy, PC, CC, BusCat, TP, Amt2,Amt1) values (''[batchID]'',''[Yr][Mo]'',', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '418', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1439', 'Select ''1439'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Rein Loc supressed for GL'',''Rein Loc'',x.ZZREILOC from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZREILOC <> '' and f.ReinLoc = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1440', 'Select ''1440'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Risk Ter supressed for GL'',''Risk Ter'',x.ZZRISKTER from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZRISKTER <> '' and f.RiskTerr = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
