    ('Parker Val', '1550', 'select ''1550'',x.TabName,x.RowNbr,''Doc Type'',x.BLART,''Doc Type does not support payment method'',''Pymt Meth'',x.ZLSCH from ParkerTrans0 x inner join sets s on s.ID = ''ZDT006'' and x.BLART >= s.FromVal and x.BLART <= s.ThruVal inner join sets t on t.ID = ''ZPM001'' and x.ZLSCH >= t.FromVal and x.ZLSCH <= t.ThruVal where BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
