    ('SQL-G22', '402', 'insert into TransX (KeyID, Flex1,Qtr,Date1,Crcy,Flex2,Assgnmt,GL,PK,Amt1,Amt2,Amt3,Amt4,Txt,PC,CC,TTY,RefKey3,Flex9,Flex4,RefKey2) (Select ''[batchID]'' as KeyID, Flex1,Qtr,Date1,Crcy,substring(Assgnmt,1,7) + '' '' + substring(Flex2,1,8) as Flex2,Assgnmt,''6210002'' as GL,PK,Amt1,Amt2,Amt3,Amt2 as Amt4,Txt,PC,CC,TTY,RefKey3,Flex1 as Flex9,substring(Assgnmt,1,7) as Flex4,GL as RefKey2 from TransX where KeyID = ''[batchID]-data2'' and GL = ''6210000'')', NULL, NULL, NULL, NULL, NULL, NULL),
