    ('SQL-G67', '211', 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Ledger = y.Ledger and x.Co = y.Co and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 >= 0 and x.GL like ''28%'' and y.Flex1 = ''pass1'' and x.Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
