    ('SQL-W27', '202', 'update IR17_Trigger set Flag = ''Y'', insdt = CURRENT_TIMESTAMP where Pipelinename = ''P_PL_IFRS_SAP_AzureSQL_Pull'' and GroupID = (select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr)', NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO Misc_Tables (Table_Id, ID, Descr, Field1, Field2, Field3, Field4, Field5, Field6)
VALUES
    ('Data2TabName', 'M13', 'data 2 - M12 recon', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Data3TabName', 'M13', 'data 3 - W12 recon', NULL, NULL, NULL, NULL, NULL, NULL),
