    ('SQL-G28', '165', 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Flex3,Flex4,Flex1,Flex2,Location) (select ''[batchID]-data4'' as KeyID, Co,Crcy,GL,PC,CC,Amt1 * (100-Rate2) * Rate3,Amt2 * (100-Rate2) * Rate3,Amt3 * (100-Rate2) * Rate3,CCcat, ''N'' as Deferrable_Flag, ''N'' as Attributable_Flag, Flex1, Flex2,Location from TransX where KeyID = ''[batchID]-data3'' and Rate1 < Rate2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '434', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
