    ('SQL-G28', '151', 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Rate1,Rate2,Rate3,Flex1,Flex2,Location) (select ''[batchID]-data3'' as KeyID, t.Co,t.Crcy,t.GL,t.PC,t.CC,t.Amt1,t.Amt2,t.Amt3,c.Cat_Override as CCcat, c.Deferrable * 100 as Rate1, c.Attributable * 100 as Rate2, c.Amt1 as Rate3, c.Co as Flex1, c.Portfolio_Nbr, c.Portfolio_PC as Flex2 from TransX t inner join IR17_CC c on t.CC = c.CC and t.GL = c.GL and c.Typ = ''CC_PC_GL'' where KeyID = ''[batchID]'' and Zone in (''1'',''2''))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '251', 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3) (select ''[batchID]'' as KeyID, Flex1 as Co,Crcy,Flex5 as GL,Location as PC,Flex6 as PTF,round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]-data4'' group by Flex1,Crcy,Flex5,Location,Flex6)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '311', 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3,Txt) (select KeyID, Co,Crcy,GL,PC,PTF,round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, ''Exp reclass [yyyy-mm-dd]'' as Txt from TransX where KeyID = ''[batchID]'' group by KeyID, Co,Crcy,GL,PC,PTF)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '315', 'delete from TransX where KeyID = ''[batchID]'' and Txt is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '319', 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3,Txt) (select KeyID, Co,Crcy,''2851017'' as GL,''7URCAANTP0'' as PC,'' as PTF,round(-sum(Amt1),2) as Amt1, round(sum(-Amt2),2) as Amt2, round(sum(-Amt3),2) as Amt3, ''Exp reclass [yyyy-mm-dd]'' as Txt from TransX where KeyID = ''[batchID]'' group by KeyID, Co,Crcy)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '371', 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, Amt1, Amt2, Amt3,PK) (Select KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL group by KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt)', NULL, NULL, NULL, NULL, NULL, NULL),
