    ('Parker Val', '1107', 'Select ''1107'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be QU for Elim docs with reversal dates in the month following the posting date'',''Reversal Date'',x.STODT from ParkerTrans0 x where cast(x.STODT as date) >= cast(cast(month(dateadd(month,1,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,1,PostingDate)) as varchar(4)) as date) and cast(x.STODT as date) < cast(cast(month(dateadd(month,2,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,2,PostingDate)) as varchar(4)) as date) and x.BLART in (''ZW'',''QW'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1108', 'Select ''1108'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be QR for reversal dates in the second month following the posting date'',''Reversal Date'',x.STODT from ParkerTrans0 x where cast(x.STODT as date) >= cast(cast(month(dateadd(month,2,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,2,PostingDate)) as varchar(4)) as date) and cast(x.STODT as date) < cast(cast(month(dateadd(month,3,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,3,PostingDate)) as varchar(4)) as date) and not x.BLART in (''QR'',''ZW'',''QW'',''QU'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1109', 'Select ''1109'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be QW for Elim docs with reversal dates in the second month following the posting date'',''Reversal Date'',x.STODT from ParkerTrans0 x where cast(x.STODT as date) >= cast(cast(month(dateadd(month,2,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,2,PostingDate)) as varchar(4)) as date) and cast(x.STODT as date) < cast(cast(month(dateadd(month,3,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,3,PostingDate)) as varchar(4)) as date) and x.BLART in (''ZW'',''QU'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1110', 'Select ''1110'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be QQ or YA,YB,YC for reversal dates in the last month of the quarter following the posting date'',''Reversal Date'',x.STODT from ParkerTrans0 x where cast(x.STODT as date) >= cast(cast(month(dateadd(month,(floor((month(PostingDate)-1)/3)+2)*3-month(PostingDate),PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,(floor((month(PostingDate)-1)/3)+2)*3-month(PostingDate),PostingDate)) as varchar(4)) as date) and cast(x.STODT as date) < cast(cast(month(dateadd(month,(floor((month(PostingDate)-1)/3)+2)*3-month(PostingDate)+1,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,(floor((month(PostingDate)-1)/3)+2)*3-month(PostingDate)+1,PostingDate)) as varchar(4)) as date) and not x.BLART in (''QQ'',''YA'',''YB'',''YC'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1111', 'Select ''1111'',x.TabName,x.RowNbr,''DocType'',x.BLART,''Reference required for Doc Type'',''Reference'',x.XBLNR from ParkerTrans0 x where x.XBLNR = '' and x.BLART in (''AQ'',''CA'',''KA'',''KR'',''KW'',''QA'',''SA'',''XA'',''YA'',''YB'',''YC'',''YD'',''ZM'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G25', '211', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1011', 'insert into ParkerTrans0 (BatchID,RowNbr,Validated,Filename,TabName,BUKRS,BLART,WAERS,LDGRP,DocDate,PostingDate,BLDAT,BUDAT,XBLNR,BKTXT,GJAHR,MONAT,USNAM,TCODE,AWTYP,ACC_PRINCIPLE,DOC_STATUS,DocNbr,HWAER,HWAE2,HWAE3,Flex1,Flex2,Flex3,BUZEI,NEWBS,KOART,KTOSL,HKONT,NEWKO,Amt1,Amt2,Amt3,Amt4,SGTXT,PRCTR,ValueDate,VALUT,WWERT,TransDate) (select BatchID,1 as RowNbr,Validated,Filename,TabName,BUKRS,BLART,WAERS,LDGRP,DocDate,PostingDate,BLDAT,BUDAT,XBLNR,BKTXT,GJAHR,MONAT,USNAM,TCODE,AWTYP,ACC_PRINCIPLE,DOC_STATUS,DocNbr,HWAER,HWAE2,HWAE3,Flex1,Flex2,Flex3,''2'' as BUZEI,''50'' as NEWBS,KOART,KTOSL,''4398600'' as HKONT,''4398600'' as NEWKO,(case when Amt1 > 0 and (Amt1 <= [cbxBalance] or coalesce(Amt5,0) = 0) then -Amt1 else 0 end) as Amt1,(case when Amt2 > 0 and (Amt2 <= [cbxBalance] or coalesce(Amt6,0) = 0) then -Amt2 else 0 end) as Amt2,(case when Amt3 > 0 and (Amt3 <= [cbxBalance] or coalesce(Amt7,0) = 0 or BLART = ''RI'') then -Amt3 else 0 end) as Amt3,(case when Amt4 > 0 and (Amt4 <= [cbxBalance] or coalesce(Amt8,0) = 0) then -Amt4 else 0 end) as Amt4,''Auto balancing'' as SGTXT,PRCTR,ValueDate,VALUT,WWERT,TransDate from ParkerTrans0 where BatchID = ''[BatchID]'' and BUZEI = ''1'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G92', '304', 'insert into TransX (KeyID, GL, Crcy,Amt1,Amt2,Amt3,Amt4,Co,PC,TP) (Select KeyID, ''2899901'' as GL, ''SGD'' as Crcy, round(sum(-Amt1),2) as Amt1, round(sum(-Amt3),2) as Amt2, round(sum(-Amt3),2) as Amt3, round(sum(-Amt1),2) as Amt4, ''2008'' as Co,''1400000000'' as PC, ''2005'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Crcy Codes', 'KMF', 'Comoros Franc', NULL, '196', NULL, 'dropdown', NULL, NULL),
    ('Crcy Codes', 'KPW', 'North Korean Won', NULL, '197', NULL, 'dropdown', NULL, NULL),
