    ('Crcy Codes', 'KZT', 'Kazakstanian Tenge', NULL, '201', NULL, 'dropdown', NULL, NULL),
    ('Crcy Codes', 'LAK', 'Laotian Kip', NULL, '202', NULL, 'dropdown', NULL, NULL),
    ('Crcy Codes', 'LBP', 'Lebanese Pound', NULL, '203', NULL, 'dropdown', NULL, NULL),
