    ('Crcy Codes', 'LRD', 'Liberian Dollar', NULL, '205', NULL, 'dropdown', NULL, NULL),
    ('Parker Val', '1012', 'insert into ParkerTrans0 (BatchID,RowNbr,Validated,Filename,TabName,BUKRS,BLART,WAERS,LDGRP,DocDate,PostingDate,BLDAT,BUDAT,XBLNR,BKTXT,GJAHR,MONAT,USNAM,TCODE,AWTYP,ACC_PRINCIPLE,DOC_STATUS,DocNbr,HWAER,HWAE2,HWAE3,Flex1,Flex2,Flex3,BUZEI,NEWBS,KOART,KTOSL,HKONT,NEWKO,Amt1,Amt2,Amt3,Amt4,SGTXT,PRCTR,ValueDate,VALUT,WWERT,TransDate) (select BatchID,2 as RowNbr,Validated,Filename,TabName,BUKRS,BLART,WAERS,LDGRP,DocDate,PostingDate,BLDAT,BUDAT,XBLNR,BKTXT,GJAHR,MONAT,USNAM,TCODE,AWTYP,ACC_PRINCIPLE,DOC_STATUS,DocNbr,HWAER,HWAE2,HWAE3,Flex1,Flex2,Flex3,''2'' as BUZEI,''40'' as NEWBS,KOART,KTOSL,''4398600'' as HKONT,''4398600'' as NEWKO,(case when Amt1 < 0 and (Amt1 >= -[cbxBalance] or coalesce(Amt5,0) = 0) then -Amt1 else 0 end) as Amt1,(case when Amt2 < 0 and (Amt2 >= -[cbxBalance] or coalesce(Amt6,0) = 0) then -Amt2 else 0 end) as Amt2,(case when Amt3 < 0 and (Amt3 >= -[cbxBalance] or coalesce(Amt7,0) = 0 or BLART = ''RI'') then -Amt3 else 0 end) as Amt3,(case when Amt4 < 0 and (Amt4 >= -[cbxBalance] or coalesce(Amt8,0) = 0) then -Amt4 else 0 end) as Amt4,''Auto balancing'' as SGTXT,PRCTR,ValueDate,VALUT,WWERT,TransDate from ParkerTrans0 where BatchID = ''[BatchID]'' and BUZEI = ''1'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1013', 'delete from ParkerTrans0 where BatchID = ''[BatchID]'' and RowNbr in (1,2) and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1014', 'update x set Amt1 = y.Amt1, Amt2 = y.Amt2, Amt3 = y.Amt3, Amt4 = y.Amt4 from ParkerTrans0 x inner join (select DocNbr, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4 from ParkerTrans0 x where BatchID = ''[BatchID]'' and (RowNbr in (1,2) or BUZEI = 1) group by DocNbr) y on x.DocNbr = y.DocNbr where x.BatchID = ''[BatchID]'' and x.BUZEI = ''1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1015', 'update x set DocAmt = x.Amt1, LCamt = x.Amt2, LC2amt = x.Amt3, LC3amt = x.Amt4, WRBTR = x.Amt1, DMBTR = x.Amt2, DMBE2 = x.Amt3, DMBE3 = x.Amt4, PRCTR = y.DefaultPC, ZUONR = '', KOSTL = '', VBUND = '', BEWAR = '', ZZPRODUCT = '', ZZUWYEAR = '', ZZACCYEAR = '', ZZREINTY = '', ZZCONTR = '', ZZCATCOD = '', ZZPREMTR = '', ZZBROKER = '', ZZSUBPRO = '', ZZREINSN = '', ZZRISKTER = '', ZZSTATUS = '', ZZREILOC = '', ZZTRANCD = '', XREF1 = '', XREF2 = '', XREF3 = '', MWSKZ = '', AUFNR = '', ANLN1 = '', ANLN2 = '', ZTERM = '', ZLSCH = '', MENGE = '', MEINS = '', KUNNR = '', LIFNR = '', ANBWA = '' from ParkerTrans0 x inner join Companies y on x.BUKRS = y.Co where x.BatchID = ''[BatchID]'' and x.RowNbr in (1,2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1016', 'update x set RowNbr = y.RowNbr+1 from ParkerTrans0 x inner join (select DocNbr,max(RowNbr) as RowNbr from ParkerTrans0 where BatchID = ''[BatchID]'' group by DocNbr) y on x.DocNbr = y.DocNbr where x.BatchID = ''[BatchID]'' and x.RowNbr = 1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1017', 'update x set RowNbr = y.RowNbr+1 from ParkerTrans0 x inner join (select DocNbr,max(RowNbr) as RowNbr from ParkerTrans0 where BatchID = ''[BatchID]'' group by DocNbr) y on x.DocNbr = y.DocNbr where x.BatchID = ''[BatchID]'' and x.RowNbr = 2', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1018', 'Update x set BUZEI = y.BUZEI from ParkerTrans0 x inner join (select BatchID,TabName,RowNbr,DocNbr, row_number() over (partition by DocNbr order by TabName,DocNbr,RowNbr*10) BUZEI from ParkerTrans0 where BatchID = ''[BatchID]'') y on x.BatchID = y.BatchID and x.TabName = y.TabName and x.RowNbr = y.RowNbr and x.DocNbr = y.DocNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1101', 'Select ''1101'',x.TabName,x.RowNbr,''Doc#'',x.BELNR,''Document already posted.'','','' from ParkerTrans0 x where x.BELNR like ''%-%'' and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1102', 'Select ''1102'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be SQ, QR, QQ or QU, QW or YA,YB,YC for reversal dates'',''Reversal Date'',x.STODT from ParkerTrans0 x where x.STODT <> '' and not x.BLART in (''SQ'',''QR'',''QQ'',''QU'',''QW'',''YA'',''YB'',''YC'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1103', 'Select ''1103'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be SQ, QR, QQ or QU,QW or YA,YB,YC for reversal reasons'',''Reversal Reason'',x.STGRD from ParkerTrans0 x where x.STGRD <> '' and not x.BLART in (''SQ'',''QR'',''QQ'',''QU'',''QW'',''YA'',''YB'',''YC'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1104', 'Select ''1104'',x.TabName,x.RowNbr,''New co.code'',x.NEWBK,''Can not populate New co.code on first row of document'','','' from ParkerTrans0 x where x.NEWBK <> '' and x.BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1105', 'Select ''1105'',x.TabName,x.RowNbr,''DocType'',x.BLART,''DocType should be SQ for reversal dates in the month following the posting date'',''Reversal Date'',x.STODT from ParkerTrans0 x where cast(x.STODT as date) >= cast(cast(month(dateadd(month,1,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,1,PostingDate)) as varchar(4)) as date) and cast(x.STODT as date) < cast(cast(month(dateadd(month,2,PostingDate)) as varchar(2)) + ''-01-'' + cast(year(dateadd(month,2,PostingDate)) as varchar(4)) as date) and not x.BLART in (''SQ'',''ZI'',''ZW'',''QU'',''QW'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1112', 'Select ''1112'',x.TabName,x.RowNbr,''DocType'',x.BLART,''Doc Hdr Text required for Doc Type'',''Doc Hdr Text'',x.BKTXT from ParkerTrans0 x where x.BKTXT = '' and x.BLART in (''AQ'',''CA'',''QA'',''SA'',''XA'',''YA'',''YB'',''YC'',''YD'',''ZM'') and BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('ReconExcelHdrs1', 'M13', 'Co,GL,GLdesc,BusCat,PC,PCdesc,Amt1,Amt2,Amt3,Amt4,Amt7,Amt8,Amt5,Amt6', NULL, NULL, NULL, NULL, NULL, NULL),
    ('ReconExcelHdrs2', 'M13', 'Co,GL,GL Desc,ACD,PC,Portfolio PC,SAP QTD,SAP ITD,Ctrl QTD,Ctrl ITD,Late QTD,Late ITD,Var QTD,Var ITD', NULL, NULL, NULL, NULL, NULL, NULL),
