    ('SQL-W21', '401', 'update gfsdb[version].CorpAcct_Apps.dbo.IR17_Trigger set Flag = ''Y'', insdt = CURRENT_TIMESTAMP  where Pipelinename = ''P_PL_IFRS_SAP_AzureSQL_Pull'' and GroupID = (select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr)', NULL, NULL, NULL, NULL, NULL, NULL),
