    ('SkipExcelDump', 'W21', '', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Writes', 'W21', 'IFRS-17 Set Trigger on Dev/UAT', 'IFRS-17 Set Trigger on Dev/UAT', NULL, NULL, NULL, NULL, NULL),
