    ('SQL-W21', '411', '[ReplaceConnString][OriginalConnString]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G92', '303', 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,''SGD'' as Crcy,''2008'' as Co,''5USA000080'' as CC,''2SFA310005'' as Contract,Amt1 as Amt1, Amt3 as Amt2, Amt3 as Amt3, Amt1 as Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G30', '232', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3,Flex2) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3,'' as Flex2 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TP, ProdCode)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G30', '233', 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G30', '234', 'delete from TransX where KeyID = ''[batchID]'' and Flex2 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1332', 'Select ''1332'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Period closed for GL, Ledger combination.'',''Ledger'',y.Ledger from ParkerTrans0 x inner join CoLedger w on x.BUKRS = w.Co and w.Ledger in (''US'') inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Ledger in (''US'') inner join Companies z on x.BUKRS = z.Co inner join Misc_Tables t on z.Period = t.Descr and t.Table_ID = ''PeriodStatus'' and t.ID = ''GAAP2Stat'' inner join PeriodStatus p on t.Field1 = p.Variant and x.NEWKO >= p.FromAcct and x.NEWKO <= p.ThruAcct and p.AccType = ''S'' left join Misc_Tables m on x.USNAM = m.Descr and m.Table_ID = ''PeriodStatus'' and coalesce(m.ID,'') = ''AuthGrp Z001'' where ((year(x.BUDAT)*100+month(x.BUDAT)) < (p.FromYr*100+p.FromPer) or (year(x.BUDAT)*100+month(x.BUDAT)) > (p.ThruYr*100+p.ThruPer)) and not (coalesce(m.ID,'') = ''AuthGrp Z001'' and (year(x.BUDAT)*100+month(x.BUDAT)) >= (p.SuperFromYr*100+p.SuperFromPer) and (year(x.BUDAT)*100+month(x.BUDAT)) <= (p.SuperThruYr*100+p.SuperThruPer)) and not x.NEWBS in (''21'',''25'',''31'',''35'') and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr,Ledger', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1333', 'Select ''1333'',v.TabName,v.RowNbr,''GL'',v.NEWKO,''Period closed for GL, Ledger combination.'',''Ledger'',min(v.Ledger) from (Select x.TabName,x.RowNbr,x.NEWKO,y.Ledger from ParkerTrans0 x inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Ledger in (''LG'',''LS'',''MA'',''0L'') inner join Misc_Tables t on x.BUKRS like t.Field2 and y.Ledger = t.Field1 and t.Table_ID = ''PeriodStatus'' and t.ID = ''Local'' inner join PeriodStatus p on t.Descr = p.Variant and p.RecType = ''0'' left join Misc_Tables m on x.USNAM = m.Descr and m.Table_ID = ''PeriodStatus'' and coalesce(m.ID,'') = ''AuthGrp Z001'' where ((year(x.BUDAT)*100+month(x.BUDAT)) < (p.FromYr*100+p.FromPer) or (year(x.BUDAT)*100+month(x.BUDAT)) > (p.ThruYr*100+p.ThruPer)) and not (coalesce(m.ID,'') = ''AuthGrp Z001'' and (year(x.BUDAT)*100+month(x.BUDAT)) >= (p.SuperFromYr*100+p.SuperFromPer) and (year(x.BUDAT)*100+month(x.BUDAT)) <= (p.SuperThruYr*100+p.SuperThruPer)) and not x.NEWBS in (''21'',''25'',''31'',''35'') and x.BatchID = ''[BatchID]'') v group by v.TabName, v.RowNbr, v.NEWKO order by v.TabName, v.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1334', 'Select ''1334'',x.TabName,x.RowNbr,''Co'',x.BUKRS,''Company closed.'','','' from ParkerTrans0 x inner join Companies z on x.BUKRS = z.Co where z.Period = ''9999'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1335', 'Select ''1335'',v.TabName,v.RowNbr,''GL'',v.NEWKO,''Period closed for GL, Ledger combination for non I cctr.'',''Ledger'',max(v.Ledger) from (Select x.TabName,x.RowNbr,x.NEWKO,y.Ledger from ParkerTrans0 x inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Ledger in (''0L'',''IF'',''UG'') inner join Companies z on x.BUKRS = z.Co inner join PeriodStatus p on z.Period = p.Variant and ''6000000'' >= p.FromAcct and ''6000000'' <= p.ThruAcct and p.AccType = ''S'' left join Misc_Tables m on x.USNAM = m.Descr and m.Table_ID = ''PeriodStatus'' and coalesce(m.ID,'') = ''AuthGrp Z001'' where ((year(x.BUDAT)*100+month(x.BUDAT)) < (p.FromYr*100+p.FromPer) or (year(x.BUDAT)*100+month(x.BUDAT)) > (p.ThruYr*100+p.ThruPer)) and not (coalesce(m.ID,'') = ''AuthGrp Z001'' and (year(x.BUDAT)*100+month(x.BUDAT)) >= (p.SuperFromYr*100+p.SuperFromPer) and (year(x.BUDAT)*100+month(x.BUDAT)) <= (p.SuperThruYr*100+p.SuperThruPer)) and not x.NEWBS in (''21'',''25'',''31'',''35'') and x.NEWKO in (''6413001'',''6419002'',''6419006'',''6510000'') and substring(x.KOSTL,4,1) <> ''I'' and x.BatchID = ''[BatchID]'') v group by v.TabName, v.RowNbr, v.NEWKO order by v.TabName, v.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1336', 'Select ''1336'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Period closed for GL, Ledger combination for non I cctr.'',''Ledger'',y.Ledger from ParkerTrans0 x inner join CoLedger w on x.BUKRS = w.Co and w.Ledger in (''US'') inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Ledger in (''US'') inner join Companies z on x.BUKRS = z.Co inner join Misc_Tables t on z.Period = t.Descr and t.Table_ID = ''PeriodStatus'' and t.ID = ''GAAP2Stat'' inner join PeriodStatus p on t.Field1 = p.Variant and ''6000000'' >= p.FromAcct and ''6000000'' <= p.ThruAcct and p.AccType = ''S'' left join Misc_Tables m on x.USNAM = m.Descr and m.Table_ID = ''PeriodStatus'' and coalesce(m.ID,'') = ''AuthGrp Z001'' where ((year(x.BUDAT)*100+month(x.BUDAT)) < (p.FromYr*100+p.FromPer) or (year(x.BUDAT)*100+month(x.BUDAT)) > (p.ThruYr*100+p.ThruPer)) and not (coalesce(m.ID,'') = ''AuthGrp Z001'' and (year(x.BUDAT)*100+month(x.BUDAT)) >= (p.SuperFromYr*100+p.SuperFromPer) and (year(x.BUDAT)*100+month(x.BUDAT)) <= (p.SuperThruYr*100+p.SuperThruPer)) and not x.NEWBS in (''21'',''25'',''31'',''35'') and x.NEWKO in (''6413001'',''6419002'',''6419006'',''6510000'') and substring(x.KOSTL,4,1) <> ''I'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr,Ledger', NULL, NULL, NULL, NULL, NULL, NULL),
