    ('SQL-M13', '432', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Canada where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Canada x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '508', 'Insert into IR17_Other_HudCAD (Co,Crcy,Co_Crcy,YearPeriod,GL,GL_Desc,PC,PC_Desc,Program,CC,CC_Desc,CCCat,CCCat_Desc,TP,Source,Incl_Excl,ACD,Portfolio_PC,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select Co,Crcy,Flex1,YearPeriod,GL,GLDesc,PC,PCdesc,Flex3,CC,CCdesc,CCCat,Flex5,TP,''R67'',Flex4,''A'',Flex9,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC', NULL, NULL, NULL, NULL, NULL, NULL),
