    ('SQL-R49', '261', 'insert into TransX (KeyID,YearPeriod,Ledger,Co,GL,GLdesc,FSitemDesc,TP,TPname,PC,PCdesc,Hierarchy,BusCat,Contract,Flex1,Flex2,Flex3,Flex4,Amt1,Amt2,Amt3,PK) (select KeyID,YearPeriod,Ledger,Co,GL,GLdesc,FSitemDesc,TP,TPname,PC,PCdesc,Hierarchy,BusCat,Contract,Flex1,Flex2,Flex3,Flex4, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, ''99'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID,YearPeriod,Ledger,Co,GL,GLdesc,FSitemDesc,TP,TPname,PC,PCdesc,Hierarchy,BusCat,Contract,Flex1,Flex2,Flex3,Flex4)', NULL, NULL, NULL, NULL, NULL, NULL),
