    ('Parker Val', '1544', 'select  ''1544'',x.TabName,x.RowNbr,''Co-GL'',x.BUKRS + ''-'' + x.HKONT,''4th character of CCtr ""E"" not allowed for this Co-GL combination'',''CCtr'',x.KOSTL from ParkerTrans0 x inner join sets s on s.ID = ''ZGL029'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZCC001'' and x.KOSTL >= t.FromVal and x.KOSTL <= t.ThruVal left join sets u on u.ID = ''ZCO001'' and x.BUKRS >= u.FromVal and x.BUKRS <= u.ThruVal left join sets v on v.ID = ''ZCC002'' and x.KOSTL >= v.FromVal and x.KOSTL <= v.ThruVal left join sets w on w.ID = ''ZGL042'' and x.HKONT >= w.FromVal and x.HKONT <= w.ThruVal where t.ID is NULL and u.ID is NULL and (v.ID is NULL or w.ID is NULL) and substring(x.KOSTL,4,1) = ''E'' and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1545', 'select ''1545'',x.TabName,x.RowNbr,''Co-GL'',x.BUKRS + ''-'' + x.HKONT,''Only specific "E" cost centers (ZCC001 set) allowed for this Co-GL combination'',''CCtr'',x.KOSTL from ParkerTrans0 x left join sets s on s.ID = ''ZGL034'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZCC001'' and x.KOSTL >= t.FromVal and x.KOSTL <= t.ThruVal left join sets u on u.ID = ''ZCO001'' and x.BUKRS >= u.FromVal and x.BUKRS <= u.ThruVal where u.ID is NULL and ( (s.ID is NULL and t.ID is not NULL) or (s.ID is not NULL and t.ID is NULL) ) and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1555', 'select ''1555'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Contract# is required for GL'','','' from ParkerTrans0 x inner join sets s on s.ID = ''ZGL046'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZDT009'' and x.BLART >= t.FromVal and x.BLART <= t.ThruVal where x.ZZCONTR = '' and t.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
