    ('SQL-M13', '421', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt1) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_ITD),2) from IR17_Control where YearPeriod = ''[Yr][Mo]'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '422', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control where YearPeriod <= ''[Yr][Mo]'' and GL < ''4000000'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '423', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control where YearPeriod <= ''[Yr][Mo]'' and YearPeriod >= ''[Yr]01'' and GL >= ''4000000'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '431', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC_Amt from (select Co,GL,PC,ACD, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_Canada where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC_QTD),2) as LC_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC_Amt) > 1 and substring(''[BudAct]'',1,7) = ''LG-CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '433', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_Canada where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC_QTD),2) as LC_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG-CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1444', 'Select ''1444'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Sub Producer supressed for GL'',''Sub Producer'',x.ZZSUBPRO from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZSUBPRO <> '' and f.SubProd = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
