    ('Parker Val', '1446', 'Select ''1446'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Status supressed for GL'',''Status'',x.ZZSTATUS from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZSTATUS <> '' and f.Stat = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
