    ('Parker Val', '1306', 'Select ''1306'',x.TabName,x.RowNbr,''Asset#'',x.ANLN1 + ''-'' + x.ANLN2,''Does not exist for that company code.'',''Co'',x.BUKRS from ParkerTrans0 x left join Assets y on x.ANLN1 = y.Asset and x.ANLN2 = y.SubNbr and x.BUKRS = y.Co where x.ANLN1 <> '' and y.Asset is NULL and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1307', 'Select ''1307'',x.TabName,x.RowNbr,''Ledger'',y.Ledger,''Ledger does not exist for that company code.'',''Co'',x.BUKRS from ParkerTrans0 x inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Lead = ''y'' left join CoLedger z on y.Ledger = z.Ledger and x.BUKRS = z.Co where z.Co is NULL and x.BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1308', 'Select ''1308'',x.TabName,x.RowNbr,''Doc Type'',x.BLART,''Doc Type does not exist for that company code.'',''Co'',x.BUKRS from ParkerTrans0 x inner join DocType y on x.BLART = y.DocType left join DocNbrRange z on y.DocTypeNo = z.DocTypeNo and x.BUKRS = z.Co and (z.Yr = ''9999'' or z.Yr = x.GJAHR) where z.Co is NULL and x.BUZEI = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1309', 'Select ''1309'',x.TabName,x.RowNbr,''CCtr'',x.ZZCONTR,''Does not exist for that company code.'',''Co'',''4110'' from ParkerTrans0 x left join CCtrs y on x.ZZCONTR = y.CCtr and y.Co = ''4110'' where x.ZZCONTR <> '' and y.CCtr is NULL and x.BatchID = ''[BatchID]'' and x.BUKRS = ''9110'' and not x.BLART in (''YA'',''ZN'',''ZZ'') order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1311', 'Select ''1311'',x.TabName,x.RowNbr,''PCtr'',x.PRCTR,''Blocked for posting.'','','' from ParkerTrans0 x inner join PCtrs y on x.PRCTR = y.Pctr where x.PRCTR <> '' and y.Blocked = ''X'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1312', 'Select ''1312'',x.TabName,x.RowNbr,''CCtr'',x.KOSTL,''Blocked for posting.'',''Replacement CC'',(case when coalesce(y.ReplacementCC,'') = '' then ''none'' else y.ReplacementCC end) from ParkerTrans0 x inner join CCtrs y on x.KOSTL = y.CCtr where x.KOSTL <> '' and y.BlockAct = ''X'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1313', 'Select ''1313'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Blocked for posting.'','','' from ParkerTrans0 x inner join COA y on x.NEWKO = y.GL where x.NEWBS in (''40'',''50'') and y.Blocked in (''Actual'',''Both'',''Delete'') and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1314', 'Select ''1314'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Blocked for posting for that company code.'',''Co'',x.BUKRS from ParkerTrans0 x inner join COAxCo y on x.NEWKO = y.GL and x.BUKRS = y.Co where x.NEWBS in (''40'',''50'') and y.Blocked in (''Yes'',''Del'') and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
