    ('SQL-M13', '456', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data7'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Singapore where source = ''R68'' and YearPeriod = ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Singapore x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod = ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and not GL_Grp in (''WP'',''COMM'',''WPx'',''COMMx'',''DAC'',''IBNR'',''UPR'') and substring(''[BudAct]'',1,7) = ''LS-SING'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '458', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '459', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G29', '463', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''2851017'' as GL, Crcy, ''990'' as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, '' as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL like ''6%'' and not GL like ''682%'' and not GL = ''6915002'' and not substring(CC,4,1) in (''I'',''E''))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('FailIfRecordFound', 'W21', 'select * from gfsdb[version].CorpAcct_Apps.dbo.IR17_trigger where groupid =(select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr)and flag in (''Y'',''P'')', 'Pipeline trigger already set with status ''[1]'' since [2]', 'select case flag when ''P'' then ''running'' else ''waiting'' end from gfsdb[version].CorpAcct_Apps.dbo.IR17_trigger where groupid =(select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr) and flag in (''Y'',''P'')', 'select insdt from gfsdb[version].CorpAcct_Apps.dbo.IR17_trigger where groupid = (select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr) and flag in (''Y'',''P'')', NULL, NULL, NULL),
    ('Data2ExcelOrderBy', 'M28', 'Flex1', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '460', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data11'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Singapore where source = ''R64'' and YearPeriod > ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Singapore x left join IR17_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join IR17_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD ) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) AND NOT GL_Grp IN (''DAC'',''UPR'') and substring(''[BudAct]'',1,7) = ''LS-SING'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '461', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt1) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_ITD),2) from IR17_Control_Singapore where YearPeriod = ''[Yr][Mo]'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '462', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control_Singapore where YearPeriod <= ''[Yr][Mo]'' and GL < ''4000000'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '463', 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control_Singapore where YearPeriod <= ''[Yr][Mo]'' and YearPeriod >= ''[Yr]01'' and GL >= ''4000000'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '244', 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and m.Field1 = '' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL and not GL in (''2853500'',''2851017'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '261', 'Update TransX set TTY = ''900'' where KeyID = ''[batchID]'' and GL = ''1099917', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '471', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC_Amt from (select Co,GL,PC,ACD, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_HudCAD where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC_QTD),2) as LC_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC_Amt) > 1 and substring(''[BudAct]'',1,7) = ''LG-HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '472', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_HudCAD where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_HudCAD x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '473', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC_QTD),2) as LC_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG-CAD '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '474', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1315', 'Select ''1315'',x.TabName,x.RowNbr,''Asset#'',x.ANLN1 + ''-'' + x.ANLN2,''Asset closed.'',''Close Date'',y.Clsd from ParkerTrans0 x inner join Assets y on x.ANLN1 = y.Asset and x.ANLN2 = y.SubNbr where x.ANLN1 <> '' and y.Clsd <> '' and convert(varchar(8),cast(x.BUDAT as date),112) > y.Clsd and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1316', 'Select ''1316'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Recon/OpenItem GL blocked for posting for that company code.'',''Co'',x.BUKRS from ParkerTrans0 x inner join COAxCo y on x.NEWKO = y.GL and x.BUKRS = y.Co where x.NEWBS in (''40'',''50'') and y.Flex1 <> '' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '476', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data7'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_HudCAD where source = ''R68'' and YearPeriod = ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_HudCAD x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod = ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and not GL_Grp in (''WP'',''COMM'',''WPx'',''COMMx'',''DAC'',''IBNR'',''UPR'') and substring(''[BudAct]'',1,7) = ''LG_HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '287', 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC,''803'' as TTY, TP, BusCat, coalesce(Assgnmt,''), ''U1801'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600052'' and Assgnmt like ''% 805'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '313', 'update TransX set  TTY = ''607'' where KeyID = ''[batchID]''  and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and TTY = '' and GL in (''2150000'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '433', 'update TransX set ProdCode = ''U1892'', PTF = ''U3650'' from TransX where KeyID = ''[batchID]'' and GL = ''4600000'' and coalesce(ProdCode,'') = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('LedgerSelect', 'G46a', 'IF', 'a', NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '478', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M13', '479', 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1317', 'Select ''1317'',x.TabName,x.RowNbr,''GL+Co'',x.NEWKO + ''+'' + x.BUKRS,''Currency should be '' + y.Crcy + '' for GL + Company combination.'',''Crcy'',x.WAERS from ParkerTrans0 x inner join COAxCo y on x.NEWKO = y.GL and x.BUKRS = y.Co inner join Companies z on x.BUKRS = z.Co where x.NEWBS in (''40'',''50'') and y.Crcy <> z.Crcy and y.Crcy <> x.WAERS and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1318', 'Select ''1318'',x.TabName,x.RowNbr,''CCtr'',x.ZZCONTR,''Blocked for posting.'',''Replacement CC'',(case when coalesce(y.ReplacementCC,'') = '' then ''none'' else y.ReplacementCC end) from ParkerTrans0 x inner join CCtrs y on x.ZZCONTR = y.CCtr where x.ZZCONTR <> '' and y.BlockAct = ''X'' and x.BatchID = ''[BatchID]'' and x.BUKRS = ''9110'' and not x.BLART in (''ZN'',''ZZ'') order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1321', 'Select Distinct ''1321'',x.TabName,''0'',''Co'',x.BUKRS,''You do not have access to park to that company.'',''User'',x.USNAM from ParkerTrans0 x left join Misc_Tables y on x.USNAM = y.ID and (x.BUKRS = y.Field1 or y.Field1 = ''all'') and y.Field3 <> ''a'' and y.Table_ID = ''UserCoAccess'' where y.Table_ID is NULL and x.BatchID = ''[BatchID]'' order by x.TabName', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1331', 'Select ''1331'',v.TabName,v.RowNbr,''GL'',v.NEWKO,''Period closed for GL, Ledger combination.'',''Ledger'',max(v.Ledger) from (Select x.TabName,x.RowNbr,x.NEWKO,y.Ledger from ParkerTrans0 x inner join LedgerGroups y on x.LDGRP = y.LedgerGroup and y.Ledger in (''0L'',''IF'',''UG'') inner join Companies z on x.BUKRS = z.Co inner join PeriodStatus p on z.Period = p.Variant and x.NEWKO >= p.FromAcct and x.NEWKO <= p.ThruAcct and p.AccType = ''S'' left join Misc_Tables m on x.USNAM = m.Descr and m.Table_ID = ''PeriodStatus'' and coalesce(m.ID,'') = ''AuthGrp Z001'' where ((year(x.BUDAT)*100+month(x.BUDAT)) < (p.FromYr*100+p.FromPer) or (year(x.BUDAT)*100+month(x.BUDAT)) > (p.ThruYr*100+p.ThruPer)) and not (coalesce(m.ID,'') = ''AuthGrp Z001'' and (year(x.BUDAT)*100+month(x.BUDAT)) >= (p.SuperFromYr*100+p.SuperFromPer) and (year(x.BUDAT)*100+month(x.BUDAT)) <= (p.SuperThruYr*100+p.SuperThruPer)) and not x.NEWBS in (''21'',''25'',''31'',''35'') and x.BatchID = ''[BatchID]'') v group by v.TabName, v.RowNbr, v.NEWKO order by v.TabName, v.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1354', 'Select ''1354'',x.TabName,x.RowNbr,''Asset#'',x.ANLN1 + ''-'' + ANLN2,''Unit of Measure required for Asset#'','','' from ParkerTrans0 x where x.ANLN1 <> '' and x.MEINS = '' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '717', 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and c.TTY = ''990'' and substring(t.GL,4,3) = ''999'' and c.BC_From = '' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('GLSUs', 'G29', 'IR17 Late RI reload', 'IR17 Late RI reload', NULL, NULL, NULL, NULL, NULL),
    ('SQL-W11', '507', 'Delete from IR17_Control_HudCAD where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' and not coalesce(Flex2,'') like ''%adj%'' ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1410', 'Select ''1410'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Risk Ter required for GL'',''Risk Ter'','' from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZRISKTER = '' and f.RiskTerr = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1411', 'Select ''1411'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Cat Code required for GL'',''Cat Code'','' from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZCATCOD = '' and f.CatCode = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '197', 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, GL, Assgnmt, Crcy, ''806'' as TTY, TP, BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''4'' and GL like ''231%'' and TTY = ''809'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '224', 'delete from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '106', 'insert into TransX (KeyID, Co, GL, Crcy, PC, PTF, SubProd, Amt1, Amt2, Amt3) (Select ''[batchID]-data7'' as KeyID, Co, GL, Crcy, PC, PTF, SubProd, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''6''  and not PTF = ''U3460'' and not SubProd = ''TPA'' group by Co, GL, Crcy, PC, PTF, SubProd)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G28', '152', 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Rate1,Rate2,Rate3,Flex1,Flex2,Location) (select ''[batchID]-data3'' as KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,substring(CC,4,1) as CCcat, 0 as Rate1, 100 as Rate2, 1 as Rate3, ''5990'' as Flex1, ''1'' as Location, ''7URCAANTP0'' as Flex2 from TransX where KeyID = ''[batchID]'' and Zone in (''1'',''2'') and substring(CC,4,1) in (''I'',''E''))', NULL, NULL, NULL, NULL, NULL, NULL),
