    ('SQL-R49', '108', 'insert into TransX (KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY, Amt2,Amt4,Amt5,Flex6) (select KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY, round(sum(Amt2),2) as Amt2, round(sum(Amt4),2) as Amt4, round(sum(Amt5),2) as Amt5,'' as Flex6 from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W11', '508', 'Insert into IR17_Control_HudCAD (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G12', '244', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, '' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) <> ''89'' and TP <> '')', NULL, NULL, NULL, NULL, NULL, NULL),
