    ('Parker Val', '1412', 'Select ''1412'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''PTF required for GL'',''PTF'','' from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZPREMTR = '' and f.PTF = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
