    ('Parker Val', '1414', 'Select ''1414'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Sub Producer required for GL'',''Sub Producer'','' from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZSUBPRO = '' and f.SubProd = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1415', 'Select ''1415'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Reinsurer required for GL'',''Reinsurer'','' from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZREINSN = '' and f.ReinName = ''1'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1449', 'Select ''1449'',x.TabName,x.RowNbr,''Posting Key'',x.NEWBS,''Tax Code only allowed for Posting Keys 40 & 50'',''Tax Code'',x.MWSKZ from ParkerTrans0 x where x.MWSKZ <> '' and not x.NEWBS in (''40'',''50'') and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3201', 'Select ''3201'',x.TabName,x.RowNbr,''DocAmt'',x.WRBTR,''Decimal place rounding needed'',''PK'',X.NEWBS from ParkerTrans0 x where x.WRBTR <> '' and round(abs(cast(x.WRBTR as float)) - abs(DocAmt),8) <> 0 and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
