    ('Parker Val', '1450', 'select ''1450'',TabName,RowNbr,''GL'',HKONT,''4th character of CCtr must be "I" for GL'',''CCtr'',ZZCONTR from ParkerTrans0 where substring(ZZCONTR,4,1) <> ''I''  and NEWKO in (select French_GL from [Paris9002].dbo.[MapGLflip] where Odyssey_GL like ''68%'' and CoFR = ''9110'') and BatchID = ''[BatchID]'' and BUKRS = ''9110'' and not BLART in (''ZN'',''ZZ'') order by TabName,RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1501', 'select ''1501'',x.TabName,x.RowNbr,''GL'',x.HKONT,''TP supressed for GL'',''TP'',x.VBUND from ParkerTrans0 x left join sets s on s.ID in (''ZTP001'',''ZTP002'',''ZTP003'',''ZTP004'') and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal and len(s.FromVal) = len(x.HKONT) left join sets t on t.ID = ''ZCO005'' and x.BUKRS >= t.FromVal and x.BUKRS <= t.ThruVal where x.VBUND <> '' and s.ID is NULL and t.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
