    ('SQL-R34', '103', 'insert into TransX (KeyID, Co, GL, PC, TP, Amt1, Amt2, Amt3, Amt4, Flex6) (select KeyID, Co, GL, PC, TP, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass1'' as Flex6  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, PC,TP)', NULL, NULL, NULL, NULL, NULL, NULL),
