    ('SQL-R34', '112', 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Division and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R34', '113', 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Region and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
