    ('SQL-R34', '121', 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Division like m.Field2 and m.Field2 <> '' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
