    ('SQL-W13', '453', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2005'' and not ''2005 '' + Contract + '' '' + UWYR in (Select ''2005 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2005'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
