    ('SQL-W13', '321', 'Update x set Amt4 = y.DocBal, Amt5 = y.LCBal, Amt6 = y.LC2Bal from TransX x inner join (select Co,substring(GL,1,3) as GL,CC,TTY,UWYR,Contract,TransCode,sum(Amt1) as DocBal,sum(Amt2) as LCBal,sum(Amt3) as LC2Bal from TransX where KeyID = ''[batchID]'' and Flex6 = '' and Flex7 = '' and Stat = ''I'' group by Co,substring(GL,1,3),CC,TTY,UWYR,Contract,TransCode) y on x.Co = y.Co and substring(x.GL,1,3) = y.GL and x.CC = y.CC and x.TTY = y.TTY and x.UWYR = y.UWYR and x.Contract = y.Contract and x.TransCode = y.TransCode where x.KeyID = ''[batchID]'' and x.Flex6 = '' and x.Flex7 = '' and x.Stat = ''I', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '322', 'Update TransX set Flex6 = ''self TP'', Flex7 = ''self TP'' where KeyID = ''[batchID]'' and Flex6 = '' and Flex7 = '' and Stat = ''I'' and coalesce(Amt4,0) = 0 and coalesce(Amt5,0) = 0 and coalesce(Amt6,0) = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '331', 'update TransX set Flex1 = c.Crcy from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '341', 'Update x set x.PCdesc = y.Descr, x.Division = y.Program from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '342', 'Update TransX set BusCat = (case when BusCat = ''10'' then ''D'' else ''A'' end) where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '351', 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join pctrs p on x.PC = p.pctr inner join Misc_Tables m2 on m2.Field1 = p.Product and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '353', 'Update x set Flex9 = c.Portfolio_PC from TransX x inner join IR17_Contracts c on x.Contract = c.Contract and x.UWYR = c.UWYR and x.Co = c.Co where KeyID = ''[batchID]'' and not substring(x.Flex9,2,2) in (''UI'',''NL'',''EL'') and not x.Co = ''2999', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '403', 'Update TransX set Flex4 = ''Premiums'' where KeyID = ''[batchID]'' and GL = ''1310001'' and Flex4 = ''Cash'' and UWYR < ''2015', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '404', 'Update TransX set TP = ''2308'', Stat = ''X'' where KeyID = ''[batchID]'' and Contract = ''DAH'' and TP = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '405', 'Update TransX set Division = '' where KeyID = ''[batchID]'' and Division is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '421', 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '422', 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '431', 'Update TransX set Flex9 = NULL where KeyID = ''[batchID]'' and PC = ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''LG-CAD ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '441', 'update TransX set PC = ''UNKNOWN'', Flex9 = ''7UISCANTP0'' where  GL = ''2820000'' and Co = ''2300'' and BusCat = ''A'' and PC = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '451', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2001'' and not ''2001 '' + Contract + '' '' + UWYR in (Select ''2001 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2001'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '452', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2002'' and not ''2002 '' + Contract + '' '' + UWYR in (Select ''2002 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2002'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3202', 'Select ''3202'',x.TabName,x.RowNbr,''LCamt'',x.DMBTR,''Decimal place rounding needed'',''PK'',X.NEWBS from ParkerTrans0 x where x.DMBTR <> '' and round(abs(cast(x.DMBTR as float)) - abs(Lcamt),8) <> 0 and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3203', 'Select ''3203'',x.TabName,x.RowNbr,''LC2amt'',x.DMBE2,''Decimal place rounding needed'',''PK'',X.NEWBS from ParkerTrans0 x where x.DMBE2 <> '' and round(abs(cast(x.DMBE2 as float)) - abs(LC2amt),8) <> 0 and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3204', 'Select ''3204'',x.TabName,x.RowNbr,''LC3amt'',x.DMBE3,''Decimal place rounding needed'',''PK'',X.NEWBS from ParkerTrans0 x where x.DMBE3 <> '' and round(abs(cast(x.DMBE3 as float)) - abs(LC3amt),8) <> 0 and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W13', '501', 'Delete from IR17_CF where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' and not coalesce(Flex2,'') like ''%adj%', NULL, NULL, NULL, NULL, NULL, NULL),
