    ('SQL-W13', '521', 'Delete from IR17_LIC where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and GL_GRP = ''RIP'' and substring(''[BudAct]'',1,7) = ''IF-ODY ', NULL, NULL, NULL, NULL, NULL, NULL),
