    ('Parker Val', '1529', 'select ''1529'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Acc Year required for GL'','','' from ParkerTrans0 x inner join sets s on s.ID = ''ZCB001'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZDT001'' and x.BLART >= t.FromVal and x.BLART <= t.ThruVal where x.ZZACCYEAR = '' and t.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '103', 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
