    ('SQL-W14', '181', 'Update t set Co = ''3030'', Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Companies c on c.Co = t.Co inner join CrcyRates r1 on r1.Crcy = c.Crcy and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = ''GBP'' and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID = ''[batchID]'' and t.Co in (''3060'',''3100'')', NULL, NULL, NULL, NULL, NULL, NULL),
