    ('Parker Val', '1435', 'Select ''1435'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Contract supressed for GL'',''Contract'',x.ZZCONTR from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZCONTR <> '' and f.Contract = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1436', 'Select ''1436'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''UW Year supressed for GL'',''UW Year'',x.ZZUWYEAR from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZUWYEAR <> '' and f.UWYR = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '233', 'Update TransX set TP = (case when substring(FSitem,1,2) = ''00'' then substring(FSitem,3,4) else Fsitem end) where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '234', 'Update TransX set Amt1 = -Amt1, Amt2 = -Amt2, Amt3 = -Amt3 where KeyID = ''[batchID]'' and PK = ''H', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '301', 'Update x set Flex7 = y.Assgnmt from TransX x inner join TransX y on x.Co = y.Co and x.Assgnmt = y.Flex6 and x.Contract = y.Contract and x.UWYR = y.UWYR where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '302', 'Update x set Flex6 = ''self flip'', Flex7 = ''self flip'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 where x.KeyID = ''[batchID]'' and x.Flex6 = '' and x.Flex7 = '' and x.TTY = ''806'' and y.Flex6 = '' and y.Flex7 = '' and y.TTY = ''806'' and ((x.GL like ''231%'' and y.GL like ''148%'') or (x.GL like ''148%'' and y.GL like ''231%'')) and x.Assgnmt like ''%$%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '303', 'Update x set Flex6 = ''self 806'', Flex7 = ''self 806'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 and x.TTY = y.TTY where x.KeyID = ''[batchID]'' and x.Flex6 = '' and x.Flex7 = '' and x.TTY = ''806'' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '304', 'Update x set Flex6 = ''self'', Flex7 = ''self'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 where x.KeyID = ''[batchID]'' and x.Flex6 = '' and x.Flex7 = '' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '311', 'Update x set Amt4 = y.DocBal, Amt5 = y.LCBal, Amt6 = y.LC2Bal from TransX x inner join (select Co,substring(GL,1,3) as GL,CC,TTY,UWYR,Contract,TransCode,sum(Amt1) as DocBal,sum(Amt2) as LCBal,sum(Amt3) as LC2Bal from TransX where KeyID = ''[batchID]'' and Flex6 = '' and Flex7 = '' group by Co,substring(GL,1,3),CC,TTY,UWYR,Contract,TransCode) y on x.Co = y.Co and substring(x.GL,1,3) = y.GL and x.CC = y.CC and x.TTY = y.TTY and x.UWYR = y.UWYR and x.Contract = y.Contract and x.TransCode = y.TransCode where x.KeyID = ''[batchID]'' and x.Flex6 = '' and x.Flex7 = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '312', 'Update TransX set Flex6 = ''self TP'', Flex7 = ''self TP'' where KeyID = ''[batchID]'' and Flex6 = '' and Flex7 = '' and coalesce(Amt4,0) = 0 and coalesce(Amt5,0) = 0 and coalesce(Amt6,0) = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '331', 'update TransX set Flex1 = c.Crcy from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '341', 'Update x set x.PCdesc = y.Descr, x.Division = y.Program from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '351', 'Update TransX set Stat = (case when substring(GL,6,2) in (''94'',''95'',''96'',''97'',''98'') then ''E'' else ''I'' end) from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '352', 'Update TransX set Stat = ''E'' from TransX where KeyID = ''[batchID]'' and TTY in (''990'',''991'')', NULL, NULL, NULL, NULL, NULL, NULL),
