    ('SQL-W14', '361', 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join pctrs p on x.PC = p.pctr inner join Misc_Tables m2 on m2.Field1 = p.Product and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '362', 'Update x set Flex9 = c.Portfolio_PC from TransX x inner join IR17_Contracts c on x.Contract = c.Contract and x.UWYR = c.UWYR and x.Co = c.Co where KeyID = ''[batchID]'' and not substring(x.Flex9,2,2) in (''UI'',''NL'',''EL'') and not x.Co = ''2999', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '403', 'Update TransX set Flex4 = ''AnO_Cash'', Flex2 = ''07-AnOCash'' where KeyID = ''[batchID]'' and Division = ''131'' and GL like ''231%'' and CC like ''79%'' and Flex4 = ''Cash', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '405', 'Update TransX set Division = '' where KeyID = ''[batchID]'' and Division is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '421', 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '422', 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '431', 'Update TransX set Flex9 = NULL where KeyID = ''[batchID]'' and PC = ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''LG-CAD ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '451', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2001'' and not ''2001 '' + Contract + '' '' + UWYR in (Select ''2001 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2001'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '452', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2002'' and not ''2002 '' + Contract + '' '' + UWYR in (Select ''2002 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2002'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '453', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2005'' and not ''2005 '' + Contract + '' '' + UWYR in (Select ''2005 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2005'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1419', 'Select ''1419'',TabName,RowNbr,''GL'',NEWKO,''CCtr required for GL'',''CCtr'','' from ParkerTrans0  where ZZCONTR = '' and NEWKO in (select French_GL from [Paris9002].dbo.[MapGLflip] where (Odyssey_GL like ''6%'' or Odyssey_GL = ''4498000'') and CoFR = ''9110'') and BatchID = ''[BatchID]'' and BUKRS = ''9110'' and not BLART in (''ZN'',''ZZ'') order by TabName,RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1431', 'Select ''1431'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''PCtr supressed for GL'',''PCtr'',x.PRCTR from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.PRCTR <> '' and f.PC = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1432', 'Select ''1432'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''CCtr supressed for GL'',''CCtr'',x.KOSTL from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.KOSTL <> '' and f.CC = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1433', 'Select ''1433'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Product Code supressed for GL'',''Product Code'',x.ZZPRODUCT from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co inner join FSG f on c.FSG = f.FSG where x.ZZPRODUCT <> '' and f.ProdCode = ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '454', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2007'' and not ''2007 '' + Contract + '' '' + UWYR in (Select ''2007 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2007'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '455', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2008'' and not ''2008 '' + Contract + '' '' + UWYR in (Select ''2008 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2008'') ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W14', '456', 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'') and not Co + '' '' + Contract + '' '' + UWYR in (Select Co + '' '' + Contract + '' '' + UWYR from IR17_Contracts where (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'')) ) x where UWYR <> '' and Contract <> '' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR', NULL, NULL, NULL, NULL, NULL, NULL),
