    ('SQL-W15', '101', 'delete from TransX where KeyID = ''[batchID]'' and Co in (''1010'',''1099'',''2101'',''2102'',''2103'',''2500'',''4025'',''4030'',''5990'',''5992'',''5993'',''5996'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '103', 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '104', 'insert into TransX (KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC, Amt1,Amt2,Amt3,Amt4,Amt5,Amt6,Flex1) (select KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC, round(sum(coalesce(Amt1,0)),2),round(sum(coalesce(Amt2,0)),2),round(sum(coalesce(Amt3,0)),2),round(sum(coalesce(Amt4,0)),2),round(sum(coalesce(Amt5,0)),2),round(sum(coalesce(Amt6,0)),2),''pass1'' from TransX where KeyID = ''[batchID]''  group by KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '105', 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '108', 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0 and Amt5 = 0 and Amt6 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '111', 'update TransX set Amt2 = round(Amt2 + Amt1,2),Amt4 = round(Amt4 + Amt3,2),Amt6 = round(Amt6 + Amt5,2), CCcat = substring(CC,4,1), Flex1 = '', Flex2 = substring(CC,4,1), Flex4 = ''I'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '112', 'update TransX set Flex2 = ''CL'' where KeyID = ''[batchID]'' and CCCat in (''C'',''H'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '113', 'update TransX set Flex2 = ''UW'' where KeyID = ''[batchID]'' and CCCat in (''U'',''S'',''A'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '114', 'update TransX set Flex4 = ''E'' where KeyID = ''[batchID]'' and not CCCat in (''U'',''S'',''A'',''C'',''H'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '211', 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '212', 'update TransX set Flex1 = c.Crcy, Flex6 = c.Name from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '213', 'update TransX set PCdesc = p.Descr, Flex8 = p.Product, Flex3 = p.Program from TransX t inner join Pctrs p on t.PC = p.Pctr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '214', 'update TransX set CCdesc = c.Descr from TransX t inner join Cctrs c on t.CC = c.Cctr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '215', 'update TransX set Flex5 = c.Descr from TransX t inner join CCtrCats c on t.CCcat = c.Cat where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '351', 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + ''AN'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex8 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W15', '490', 'Update x set Amt1 = Amt5, Amt2 = Amt6, Amt3 = round(Amt5/c.Rate,2), Amt4 = round(Amt6/c.Rate,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
