    ('SQL-W24', '101', 'delete from TransX where KeyID = ''[batchID]'' and Co in (''1010'',''1099'',''2101'',''2102'',''2103'',''2500'',''4025'',''4030'',''5990'',''5992'',''5993'',''5996'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '103', 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '111', 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and BusCat like ''3%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '112', 'Update TransX set BusCat = ''D'' where KeyID = ''[batchID]'' and BusCat = ''10', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '113', 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and BusCat like ''2%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '114', 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''14'',''15'') and not BusCat in (''A'',''D'',''C'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '115', 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''20'',''21'',''18'') and not BusCat in (''A'',''D'',''C'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '116', 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and substring(GL,1,3) = ''287'' and not BusCat in (''A'',''D'',''C'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '117', 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and not BusCat in (''A'',''D'',''C'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '151', 'Update TransX set UWYR = ''1959'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '152', 'Update TransX set UWYR = ''1958'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = ''9999', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '202', 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '203', 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,3) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '204', 'Update TransX set Flex2 = Flex2 + ''x'' from TransX where KeyID = ''[batchID]'' and GL like ''%999%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '221', 'insert into TransX (KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,Flex5,Flex2,Amt1,Amt2,Amt3) (select KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,''N/A'' as Flex5,Flex2,round(-sum(coalesce(Amt1,0)),2),round(sum(-coalesce(Amt2,0)),2),round(sum(-coalesce(Amt3,0)),2) from TransX where KeyID = ''[batchID]''  group by KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,Flex2)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '241', 'delete from TransX where KeyID = ''[batchID]''  and Flex5 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '242', 'delete from TransX where KeyID = ''[batchID]''  and Amt1 = 0 and Amt2 = 0 and Amt3 = 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '301', 'Update x set x.PCdesc = y.Descr, x.Flex3 = y.Program, x.Flex5 = y.Product, x.Division = y.Division, x.Region = y.Region, x.Location = y.Location, x.Zone = y.Zone, x.Hierarchy = y.Hierarchy from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '302', 'Update x set x.Flex1 = y.Crcy from TransX x inner join Companies y on x.Co = y.Co where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '311', 'Update TransX set Flex4 = (case when Flex2 like ''%x'' then ''E'' else ''I'' end) from TransX where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '312', 'Update TransX set Flex4 = ''X'' where KeyID = ''[batchID]'' and len(TP) = 4', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '313', 'Update TransX set Flex4 = ''X'' where KeyID = ''[batchID]'' and Co in (''2999'',''3999'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '321', 'Update TransX set Flex6 = Division, Flex7 = rtrim(Region + '' '' + Location) where KeyID = ''[batchID]'' and Division in (''US_INS_OPS'',''LATAMER'',''FIRV'') and Flex6 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '322', 'Update TransX set Flex6 = Region, Flex7 = rtrim(Location + '' '' + Zone) where KeyID = ''[batchID]'' and Region in (''LONBRANCH'',''EUROPE'',''ASIA'',''NEWLN'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '323', 'Update TransX set Flex6 =Location, Flex7 ='' '' where KeyID = ''[batchID]'' and Location in (''CAN'',''USA'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '324', 'Update TransX set Flex6 = rtrim(Division + '' '' + Region + '' '' + Location), Flex7 = '' where KeyID = ''[batchID]'' and Flex6 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '351', 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' +(case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '352', 'Update TransX set Flex8 = Hierarchy where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '401', 'Update TransX set Flex2 = ''RCR IF'' where KeyID = ''[batchID]'' and Flex2 = ''RCR'' and Co = ''2999'' and TP like ''F%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '402', 'Update TransX set Flex2 = ''RCR IF'' where KeyID = ''[batchID]'' and Flex2 = ''RCR'' and Co = ''2999'' and TP = '' and (Contract = '' or Contract = ''RRP RECLASS'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '403', 'Update TransX set Flex4 = ''I'' where KeyID = ''[batchID]'' and Flex2 = ''RCR IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '404', 'Update TransX set TP = ''2308'', Flex4 = ''X'' where KeyID = ''[batchID]'' and Contract = ''DAH'' and TP = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '491', 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W24', '492', 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
