    ('SQL-W24', '502', 'Insert into IR17_LIC (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R68'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-ODY ', NULL, NULL, NULL, NULL, NULL, NULL),
