    ('SQL-W41', '121', 'insert into TransX (KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1, Amt1, Amt2, Amt3,Flex2) (Select KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2 , round(sum(coalesce(Amt3,0)),2) as Amt3, '' as Flex2 from TransX where KeyID = ''[batchID]'' group by KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1)', NULL, NULL, NULL, NULL, NULL, NULL),
