    ('SQL-G24', '215', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
