    ('SQL-W11', '504', 'Insert into IR17_Control_Canada (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W11', '505', 'Delete from IR17_Control_Singapore where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''IF-SING'' and not coalesce(Flex2,'') like ''%adj%'' ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-W11', '506', 'Insert into IR17_Control_Singapore (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1563', 'select ''1563'',x.TabName,x.RowNbr,''GL'',x.HKONT,''BusCat is suppressed for A/P doc types for GL'',''DocType'',x.BLART from ParkerTrans0 x inner join sets s on s.ID = ''ZDT016'' and x.BLART >= s.FromVal and x.BLART <= s.ThruVal left join sets t on t.ID = ''ZGL060'' and x.HKONT >= t.FromVal and x.HKONT <= t.ThruVal where t.ID is NULL and x.ZZREINTY <> '' and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1564', 'select ''1564'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Must use Product Code HG000 - HGZZZ for Hudson Invoice GL'',''Prod Code'',x.ZZPRODUCT from ParkerTrans0 x inner join sets s on s.ID = ''ZDT064'' and x.BLART >= s.FromVal and x.BLART <= s.ThruVal inner join sets t on t.ID = ''ZGL064'' and x.HKONT >= t.FromVal and x.HKONT <= t.ThruVal inner join sets u on u.ID = ''ZCO064'' and x.BUKRS >= u.FromVal and x.BUKRS <= u.ThruVal left join sets v on v.ID = ''ZPD064'' and x.ZZPRODUCT >= v.FromVal and x.ZZPRODUCT <= v.ThruVal where v.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1565', 'select ''1565'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Must use Product Code HIT000 - HIT999 for Hudson Invoice GL'',''Prod Code'',x.ZZPRODUCT from ParkerTrans0 x inner join sets s on s.ID = ''ZDT064'' and x.BLART >= s.FromVal and x.BLART <= s.ThruVal inner join sets t on t.ID = ''ZGL067'' and x.HKONT >= t.FromVal and x.HKONT <= t.ThruVal inner join sets u on u.ID = ''ZCO064'' and x.BUKRS >= u.FromVal and x.BUKRS <= u.ThruVal left join sets v on v.ID = ''ZPD067'' and x.ZZPRODUCT >= v.FromVal and x.ZZPRODUCT <= v.ThruVal where v.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1566', 'Select ''1566'',x.TabName,x.RowNbr,''GL'',x.NEWKO,''Tax Code supressed for GL'',''Tax Code'',x.MWSKZ from ParkerTrans0 x inner join COAxCo c on x.NEWKO = c.GL and x.BUKRS = c.Co where x.MWSKZ <> '' and c.Tax = ''No'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1567', 'Select ''1567'',x.TabName,x.RowNbr,''SubPro'',x.ZZSUBPRO,''Can only use TTY 877 with SubProducer G27'',''TTY'',x.BEWAR from ParkerTrans0 x where x.ZZSUBPRO <> ''G27'' and x.BEWAR = ''877'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1568', 'select ''1568'',x.TabName,x.RowNbr,''GL'',x.HKONT,''FFH TP not allowed for GL'',''TP'',x.VBUND from ParkerTrans0 x inner join sets s on s.ID = ''ZTP007'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZCO007'' and x.BUKRS >= t.FromVal and x.BUKRS <= t.ThruVal where x.VBUND like ''F%'' and t.ID is NULL and BatchID = ''[BatchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1610', 'select ''1610'',x.TabName,x.RowNbr,'','',''Value Date is a required field'','','' from ParkerTrans0 x where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and x.VALUT = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1611', 'select ''1611'',x.TabName,x.RowNbr,''ValueDate'',x.ValueDate,''Value Date must not be greater than today'',''Today'',cast(getdate() as date) from ParkerTrans0 x where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and x.ValueDate > cast(getdate() as date)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1620', 'select ''1620'',x.TabName,x.RowNbr,'','',''RefKey3 (EcritureDate) is a required field'','','' from ParkerTrans0 x where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and x.XREF3 = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1621', 'select ''1621'',x.TabName,x.RowNbr,''RefKey3 (EcritureDate)'',x.XRef3,''RefKey3 (EcritureDate) must be between Value Date and Posting Date'',''Value Date ** Posting Date'',x.ValueDate + '' ** '' + x.PostingDate from (Select TabName,RowNbr,XRef3,cast(ValueDate as varchar(10)) as ValueDate,cast(PostingDate as varchar(10)) as PostingDate from ParkerTrans0 x where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and isdate(x.XRef3) = 1) x where not x.XRef3 between replace(x.ValueDate,''-'','') and replace(x.PostingDate,''-'','')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1622', 'select ''1622'',x.TabName,x.RowNbr,''RefKey3 (EcritureDate)'',x.XRef3,''RefKey3 (EcritureDate) must not be a holiday'',''Holiday'',y.Descr from ParkerTrans0 x inner join Calendar y on cast(x.XRef3 as date) = y.DT where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and isdate(x.XRef3) = 1 and y.Co = ''9110', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1623', 'select ''1623'',TabName,RowNbr,''RefKey3 (EcritureDate)'',XRef3,''RefKey3 (EcritureDate) must not be on a weekend'',''Day of week'',XRef3dt from (select TabName,RowNbr,XRef3, (case when isdate(XRef3) = 1 then datename(weekday,cast(XRef3 as date)) else ''bad date'' end) as XRef3dt from ParkerTrans0 where BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'') x  where XRef3dt in (''Saturday'',''Sunday'') ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1624', 'select ''1624'',x.TabName,x.RowNbr,''RefKey3 (EcritureDate)'',x.Xref3,''RefKey3 (EcritureDate) must be in the format yyyyMMdd'','','' from ParkerTrans0 x where x.BUKRS in (''9100'',''9110'') and BatchID = ''[BatchID]'' and (isdate(x.XRef3) = 0 or isnumeric(x.XRef3) = 0 or len(x.XRef3) <> 8)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1632', 'select ''1632'',x.TabName,x.RowNbr,''PostingDate'',x.PostingDate,''Posting Date must not be a holiday'',''Holiday'',y.Descr from ParkerTrans0 x inner join Calendar y on x.PostingDate = y.DT where x.BUKRS in (''9100'',''9110'') and (x.RowNbr = 8 or not x.Flex3 like ''% BUDAT %'') and BatchID = ''[BatchID]'' and y.Co = ''9110', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1633', 'select ''1633'',x.TabName,x.RowNbr,''PostingDate'',x.PostingDate,''Posting Date must not be on a weekend'',''Day of week'',datename(weekday,x.PostingDate) from (select TabName,RowNbr,PostingDate from ParkerTrans0 where BUKRS in (''9100'',''9110'') and (RowNbr = 8 or not Flex3 like ''% BUDAT %'') and BatchID = ''[BatchID]'' and isdate(cast(PostingDate as varchar(10))) = 1) x where datepart(weekday,x.PostingDate) in (1,7)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1901', 'select ''1901'',x.TabName,x.RowNbr,''Balance'',convert(varchar(30),convert(money,x.Amt1),1),''DocAmt out of balance.'','','' from ParkerTrans0 x where BatchID = ''[BatchID]'' and x.Amt1 <> 0 and x.Amt5 <> 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1902', 'select ''1902'',x.TabName,x.RowNbr,''Balance'',convert(varchar(30),convert(money,x.Amt2),1),''LCamt out of balance.'','','' from ParkerTrans0 x where BatchID = ''[BatchID]'' and x.Amt2 <> 0 and x.Amt6 <> 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1903', 'select ''1903'',x.TabName,x.RowNbr,''Balance'',convert(varchar(30),convert(money,x.Amt3),1),''LC2amt out of balance.'','','' from ParkerTrans0 x where BatchID = ''[BatchID]'' and x.Amt3 <> 0 and x.Amt7 <> 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1904', 'select ''1904'',x.TabName,x.RowNbr,''Balance'',convert(varchar(30),convert(money,x.Amt4),1),''LC3amt out of balance.'','','' from ParkerTrans0 x where BatchID = ''[BatchID]'' and x.Amt4 <> 0 and x.Amt8 <> 0', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2001', 'select  ''2001'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and ( (NEWKO = ''4010000'') or (NEWKO = ''1310000'' and BEWAR = ''801'')) and ZZREINTY = ''10''  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''1001'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2010', 'select ''2010'',x.TabName,0,''Co'',x.BUKRS,cast(x.SAKNR as varchar(10)) + '': '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select t.TabName,t.Flex1,t.BUKRS,t.WAERS,m.ID as SAKNR,round(sum(t.LC2Amt * m.Field5),2) as LC2Amt from ParkerTrans0 t inner join Misc_Tables m on m.Table_ID = ''Val GL offset'' and t.NEWKO = m.Descr and t.ZZREINTY like m.Field1 and t.BEWAR like m.Field2 and t.BUKRS >= ''1000'' and t.BUKRS < (case when m.Field6 = ''IFRS4'' then ''5990'' else ''6000'' end) where BatchID = ''[BatchID]'' and not  m.Field6 = ''IFRS17'' group by t.TabName,t.Flex1,t.BUKRS,t.WAERS,m.ID) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = x.SAKNR where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2011', 'select ''2011'',x.TabName,0,''Co'',x.BUKRS,cast(x.SAKNR as varchar(10)) + '': '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select t.TabName,t.Flex1,''599x'' as BUKRS,t.WAERS,m.ID as SAKNR,round(sum(t.LC2Amt * m.Field5),2) as LC2Amt from ParkerTrans0 t inner join Misc_Tables m on m.Table_ID = ''Val GL offset'' and t.NEWKO = m.Descr and t.ZZREINTY like m.Field1 and t.BEWAR like m.Field2 and t.BUKRS >= ''5990'' and t.BUKRS <= ''5999'' where BatchID = ''[BatchID]'' and m.Field6 = ''IFRS17'' group by t.TabName,t.Flex1,t.WAERS,m.ID) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = x.SAKNR where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2020', 'select ''2020'',x.TabName,0,''Co'',''2xxx'',''5001: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''TTY'',''807'' from (select TabName,WAERS,Flex1,round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO in (''1480001'',''2310001'')  and BEWAR = ''807'' and BUKRS > ''2000'' and BUKRS < ''3000'' group by BatchID,TabName,WAERS,Flex1) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = ''5001'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2030', 'select ''2030'',x.TabName,0,''Co'',x.BUKRS,''5002: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''GL'',x.NEWKO from (select TabName,BUKRS,NEWKO,WAERS,Flex1,round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and (substring(NEWKO,1,2) in (''13'',''14'',''15'',''16'',''18'',''20'',''21'',''22'',''23'',''24'') or substring(NEWKO,1,3) in (''283'',''284'',''287'')) and BEWAR = ''991'' and not substring(NEWKO,6,2) in (''94'',''96'') and BUKRS < ''5990'' group by BatchID,TabName,WAERS,Flex1,BUKRS,NEWKO) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = ''5002'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2040', 'select ''2040'',x.TabName,0,''Co'',x.BUKRS,''5003: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''GL'',x.NEWKO from (select TabName,BUKRS,substring(NEWKO,1,3) + ''xxxx'' as NEWKO,WAERS,Flex1,round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO >= ''9000000'' and NEWKO < ''9900000'' group by BatchID,TabName,WAERS,Flex1,BUKRS,substring(NEWKO,1,3)) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = ''5003'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2050', 'select ''2050'',x.TabName,0,''Co'',x.BUKRS,''5004: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''GL'',''992xxxx'' from (select TabName,BUKRS,WAERS,Flex1,round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO like ''992%'' group by BatchID,TabName,WAERS,Flex1,BUKRS) x inner join Misc_Tables y on y.Table_ID = ''Val GL offset descr'' and y.ID = ''5004'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2310', 'select  ''2310'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO in (''2849996'',''4398012'')  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''2110'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2311', 'select  ''2311'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO in (''2599996'',''4398013'')  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''2111'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2312', 'select  ''2312'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO in (''2819996'',''2829996'',''2850996'',''2869996'',''4398014'')  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''2112'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2401', 'select  ''2401'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and not BUKRS in (''3030'',''9030'') and not BLART in (''FA'',''FB'') and (NEWKO in (''1937000'',''2852000'',''6832000'') or (substring(NEWKO,1,3)  in (''131'',''148'',''221'',''231'') and BEWAR = ''808''))  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''1301'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '2403', 'select  ''2403'',x.TabName,0,''Co'',x.BUKRS,''Co+Crcy balance err: '' + y.Descr + '': $'' + convert(varchar(30),convert(money,x.LC2Amt),1),''Crcy'',x.WAERS from (select TabName, BUKRS, WAERS, FLEX1, round(sum(LC2Amt),2) as LC2Amt from ParkerTrans0 where BatchID = ''[BatchID]'' and NEWKO in (''1310001'',''2210001'')  and BEWAR = ''809''  group by BUKRS, WAERS, FLEX1, TabName) x inner join Misc_Tables y on Table_ID = ''Val-Rules'' and ID = ''1303'' where (x.LC2Amt < -[cbxBalance] or x.LC2Amt > [cbxBalance]) and x.Flex1 = ''IF', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3101', 'Select ''3101'',x.TabName,x.RowNbr,''DocAmt'',x.WRBTR,''Expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''50'',''31'',''35'') and substring(x.WRBTR,1,1) <> ''-'' and x.WRBTR <> '' and x.WRBTR <> ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3102', 'Select ''3102'',x.TabName,x.RowNbr,''DocAmt'',x.WRBTR,''Not expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''40'',''70'',''21'',''25'') and substring(x.WRBTR,1,1) = ''-'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3103', 'Select ''3103'',x.TabName,x.RowNbr,''LCamt'',x.DMBTR,''Expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''50'',''31'',''35'') and substring(x.DMBTR,1,1) <> ''-'' and x.DMBTR <> '' and x.DMBTR <> ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3104', 'Select ''3104'',x.TabName,x.RowNbr,''LCamt'',x.DMBTR,''Not expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''40'',''70'',''21'',''25'') and substring(x.DMBTR,1,1) = ''-'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3105', 'Select ''3105'',x.TabName,x.RowNbr,''LC2amt'',x.DMBE2,''Expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''50'',''31'',''35'') and substring(x.DMBE2,1,1) <> ''-'' and x.DMBE2 <> '' and x.DMBE2 <> ''0'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '3106', 'Select ''3106'',x.TabName,x.RowNbr,''LC2amt'',x.DMBE2,''Not expecting a "-" as the first character'',''PK'',X.NEWBS from ParkerTrans0 x where x.NEWBS in (''40'',''70'',''21'',''25'') and substring(x.DMBE2,1,1) = ''-'' and x.BatchID = ''[BatchID]'' order by x.TabName,x.RowNbr', NULL, NULL, NULL, NULL, NULL, NULL),
