    ('SQL-R48', '351', 'update TransX set KeyID = ''[batchID]-data4'' where KeyID = ''[batchID]'' and GL in (''4019900'',''4019901'',''4119900'',''4119901'') and ''[GL]'' = ''non TP only', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G32', '219', 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, substring(GL,1,3) + ''% 804'' as Assgnmt, Crcy, '' as TTY, '' as TP, '' as BusCat, PC, Flex5, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''161'',''162'',''241'',''242'',''441'',''682'') or TTY = ''804'') and not GL in (''1610002'',''2421002'') group by KeyID,Co,Crcy,TP,PC,Flex5,substring(GL,1,3))', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-T04', '101', 'insert into TransX (KeyID,CC,Flex1,CCdesc,Co,CCCat,Flex2,Flex3,Hierarchy,PC,Flex4,RefKey1,Contract,Flex5,Flex6,RefKey2,Flex7,Flex8,Flex9,PCdesc,Txt,Division,Region,Location,Zone) (select ''[batchID]'',CCtr,c.Name,c.Descr,c.Co,Cat,c.Typ,Func,p.Hierarchy,c.PCtr,c.ValidThru,BlockAct,ReplacementCC,c.UpdatedOn,c.UpdatedBy,ExpNode,c.Hierarchy,c.Dept,c.Person,c.Flex1,c.Flex2,p.Division,p.Region,p.Location,p.Zone from CCTRS c inner join Pctrs p on c.Pctr = p.Pctr inner join (Select Co from Companies where Co in (select co from Companies c inner join ElimSelect e on ((c.Co >= e.FromVal and c.Co <= e.ThruVal and e.Oper = ''BT'') or (c.Co = e.FromVal and e.Oper = ''EQ'')) and e.IncExcl = ''I'' inner join Misc_Tables m on m.Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') and e.ElimID = ''Co:'' + m.ID) and not co in (select co from Companies c inner join ElimSelect e on ((c.Co >= e.FromVal and c.Co <= e.ThruVal and e.Oper = ''BT'') or (c.Co = e.FromVal and e.Oper = ''EQ'')) and e.IncExcl = ''E'' inner join Misc_Tables m on m.Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') and e.ElimID = ''Co:'' + m.ID)) j on c.co = j.co)', NULL, NULL, NULL, NULL, NULL, NULL),
