    ('SQL-G24', '221', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF, Flex5,Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC,PTF,Flex5)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G24', '235', 'Update x set PC = ''7'' + m1.field2 + m2.field2 + (case when x.BusCat = ''20'' then ''A'' else ''C'' end) + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
