    ('SQL-G91', '221', 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''1998900'' as GL,''5200000000'' as PC,substring(Txt,1,len(Txt)-8),Contract,'' as ProdCode,''F0118'' as TP,round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' group by KeyID,substring(Txt,1,len(Txt)-8),Contract)', NULL, NULL, NULL, NULL, NULL, NULL),
