    ('SQL-R59', '635', 'Update t set Flex4 = ''0010-049'' from TransX t inner join Misc_Tables m on t.GL = m.Descr where t.KeyID = ''[batchID]'' and t.Flex4 = ''9999-001'' and m.Table_ID = ''GAAP2Stat'' and m.ID = ''GL2JE6111'' and  cast(t.Co as varchar(10)) + m.Field2 in (select CoField2 from (select cast(a.Co as varchar(10)) + b.Field2 as CoField2,sum(Amt1) as Amt1 from TransX a inner join Misc_Tables b on a.GL = b.Descr where a.KeyID = ''[batchID]'' and a.Flex4 = ''9999-001'' and b.Table_ID = ''GAAP2Stat'' and b.ID = ''GL2JE6111'' group by a.Co,b.Field2) x where abs(x.amt1)<1)', NULL, NULL, NULL, NULL, NULL, NULL),
