    ('SQL-G73', '201', 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select x.KeyID,x.GL,''5USA000082'' as CC,y.Field1 + '' IT WG FFX [Yr]/[Mo] from '' + x.CC + '' '' + x.GL as Txt,y.Field1 as Contract,''CHGBACK'' as ProdCode,round(-x.Amt1*cast(y.Field2 as float),2) as Amt1,''pass1'' as Flex1 from TransX x, Misc_Tables y where x.KeyID = ''[batchID]'' and y.Table_ID = ''Reimburse'' and y.ID = ''G73-TP-6610004'' and x.GL = ''6610004'' and x.CC = ''5USA000062'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G73', '202', 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select x.KeyID,x.GL,''5USA000082'' as CC,y.Field1 + '' IT WG FFX [Yr]/[Mo] from '' + x.CC as Txt,y.Field1 as Contract,''CHGBACK'' as ProdCode,round(-x.Amt1*cast(y.Field2 as float),2) as Amt1,''pass1'' as Flex1 from TransX x, Misc_Tables y where x.KeyID = ''[batchID]'' and y.Table_ID = ''Reimburse'' and y.ID = ''G73-TP-GL'' and not x.GL = ''6610004'' and x.CC = ''5USA000062'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G73', '221', 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''1998900'' as GL,''1400000000'' as PC,x.Txt,x.Contract,'' as ProdCode,y.Descr as TP,round(-sum(x.Amt1),2) as Amt1 from TransX x left join Misc_Tables y on x.Contract = y.Field1 where x.KeyID = ''[batchID]'' and y.Table_ID = ''Reimburse'' and y.ID = ''G73-TP-6610004'' group by x.KeyID,x.Txt,x.Contract,y.Descr)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G80', '401', 'insert into TransX (KeyID, GL, PC, CC, Contract, ProdCode, TP, Amt1, Amt2, Amt3,PK) (Select KeyID,GL, PC, CC, Contract, ProdCode, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and not PK = ''40'')', NULL, NULL, NULL, NULL, NULL, NULL),
