    ('SQL-G71', '211', 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select KeyID,GL,CC,Txt,Contract,ProdCode,round(sum(Amt1),2) as Amt1,''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,GL,CC,Txt,Contract,ProdCode)', NULL, NULL, NULL, NULL, NULL, NULL),
