    ('SQL-G71', '222', 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''2898900'' as GL,''5200000000'' as PC,Txt,Contract,'' as ProdCode,''F0046'' as TP,ROUND((-SUM(Amt1)),2) from TransX where KeyID = ''[batchID]'' and GL = ''1998900'' and Contract = ''5USA000086'' group by KeyID,Txt,Contract)', NULL, NULL, NULL, NULL, NULL, NULL),
