    ('SQL-G12', '222', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 < 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G12', '241', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) = ''89'' and TP <> '' )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G12', '242', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) = ''89'' and TP <> '')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G12', '243', 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, '' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) <> ''89'' and TP <> '')', NULL, NULL, NULL, NULL, NULL, NULL),
