		from TransX where KeyID = ''[batchID]''  group by KeyID, Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9)', NULL, NULL, NULL, NULL, NULL, NULL),
