    ('SQL-G23', '261', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3,Assgnmt) (Select ''[batchID]-data3'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, (case when Co like ''599%'' then '' else ''x'' + Flex1 + ''x'' + Flex2 + ''x'' + Flex3 end) as Assgnmt from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Flex1, Flex2, Flex3)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G23', '262', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, BusCat, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, Crcy, ''900'' as TTY, '' as TP, PC, '' as BusCat, Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]-data3'' and Assgnmt in (''x4419901x20x'',''x6829900xx'',''x6829901xx'') and ''[yyyy-mm-dd]'' in (''2022-12-31'') group by KeyID, Co, Crcy, PC, Assgnmt)', NULL, NULL, NULL, NULL, NULL, NULL),
