    ('SQL-T05', '104', 'update TransX set Flex8 = substring(''GL: '' + c3.COA,1,254) from TransX inner join (select distinct c2.GL, (select c1.OS_GL + '','' as [text()] from (select GL,OS_GL from COA inner join (select distinct GL_From, GL_Thru, OS_GL from osAccountMap3 where Co_Thru = ''9999'') os on GL >= GL_From and GL <= GL_Thru) c1 where c1.GL = c2.GL order by c1.OS_GL for XML Path ('') ) [COA] from COA c2) c3 on TransX.GL = c3.GL where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-T05', '125', 'update TransX set Flex9 = x.OS_GL_Desc from TransX t inner join osAccountMap3 x on substring(t.Flex8,5,4) = x.OS_GL where KeyID = ''[batchID]'' and len(t.Flex8) > 4', NULL, NULL, NULL, NULL, NULL, NULL),
