    ('Parker Val', '1519', 'select ''1519'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Invalid TTY for GL'',''TTY'',x.BEWAR from ParkerTrans0 x inner join sets s on s.ID = ''ZGL012'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZTT012'' and x.BEWAR >= t.FromVal and x.BEWAR <= t.ThruVal where t.ID is NULL and x.BLART <> ''UE'' and BatchID = ''[BatchID]'' and not BUKRS in (''9002'',''9110'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1520', 'select ''1520'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Invalid TTY for GL'',''TTY'',x.BEWAR from ParkerTrans0 x inner join sets s on s.ID = ''ZGL013'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZTT013'' and x.BEWAR >= t.FromVal and x.BEWAR <= t.ThruVal where t.ID is NULL and x.BLART <> ''UE'' and BatchID = ''[BatchID]'' and not BUKRS in (''9002'',''9110'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1521', 'select ''1521'',x.TabName,x.RowNbr,''GL'',x.HKONT,''TTY is suppressed for GL (except for FX Doc Types)'',''TTY'',x.BEWAR from ParkerTrans0 x inner join sets s on s.ID = ''ZGL019'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZCO005'' and x.BUKRS >= t.FromVal and x.BUKRS <= t.ThruVal left join sets v on v.ID = ''ZDT001'' and x.BLART >= v.FromVal and x.BLART <= v.ThruVal where t.ID is NULL and v.ID is NULL and x.BLART <> ''UE'' and x.BEWAR <> '' and BatchID = ''[BatchID]'' and not BUKRS in (''9002'',''9110'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('Parker Val', '1522', 'select ''1522'',x.TabName,x.RowNbr,''GL'',x.HKONT,''Invalid TTY for GL'',''TTY'',x.BEWAR from ParkerTrans0 x inner join sets s on s.ID = ''ZGL031'' and x.HKONT >= s.FromVal and x.HKONT <= s.ThruVal left join sets t on t.ID = ''ZTT031'' and x.BEWAR >= t.FromVal and x.BEWAR <= t.ThruVal left join sets v on v.ID = ''ZDT001'' and x.BLART >= v.FromVal and x.BLART <= v.ThruVal where t.ID is NULL and v.ID is NULL and x.BLART <> ''UE'' and x.BEWAR <> '' and BatchID = ''[BatchID]'' and not BUKRS in (''9002'',''9110'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R07', '311', 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
