    ('SQL-G24', '214', 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID = ''[batchID]'')', NULL, NULL, NULL, NULL, NULL, NULL),
