    ('SQL-R59', '411', 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4, Amt1,Amt2,Flex8) (select ''[batchID]'',(case when Yr < [Yr] and GL >= ''4000000'' then ''3610000'' else (case when Yr < [Yr] and GL = ''3810001'' then ''3810000'' else GL end) end) as GL, '' as BusCatDesc,Co,Ledger,JE,Amt, (case when Yr = [Yr] then Amt else 0 end) as Amt2,''pass6'' from GAAP2Stat where Yr <= [Yr] and (CarryFwd = ''Y'' or Yr = ''[Yr]'') and (Period <= [Mo] or Yr < [Yr]) and not JE like ''%-H%'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R59', '605', 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4, Amt1,Amt2,Flex8) (select KeyID, ''1999901'', '', Co, Ledger,Flex4,round(-sum(Amt1),2),round(-sum(Amt2),2),''pass7'' from TransX where KeyID = ''[batchID]'' and Flex4 = ''0010-050'' and Co = ''2008'' group by KeyID,Co,Ledger,Flex4)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R28', '232', 'insert into TransX (KeyID, GL, Gldesc, Co, Flex1, Flex4, Flex9, Qtr, Amt2, Amt3) (select KeyID, ''1000000'' as GL, ''Colm 13'' as GLdesc, Co, SchedYname, Flex4, ''n'' as Flex9, 13 as Qtr,round(-sum(Amt2),2) as Amt2,round(-sum(Amt3),2) as Amt3 from TransX t inner join TPs p on t.Co = p.TP where KeyID = ''[batchID]'' and Qtr = 13 group by KeyID,Co,SchedYname,Flex4)', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R28', '242', 'insert into TransX (KeyID, Yr,Flex1,Flex5,Flex6,Period,Flex2,Flex9,Qtr,Amt1) (select ''[batchID]'' as KeyID,Descr,Field1,Field2,Field3,Descr,Field1,''y'' as Flex9, 9 as Qtr, 0 as Amt1 from Misc_Tables where Table_ID = ''Sched Y'' and ID = ''Names'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R16', '236', 'update TransX set Flex6 = coalesce(m.SchedFname,'') from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'' and Flex6 = ', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-E08', '1004', 'delete from TransX where KeyID = ''[batchID]'' and GL = ''1480002', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R24', '223', 'update TransX set Flex6 = ''A'' from TransX t inner join Misc_Tables m on substring(t.GL,1,5) = m.ID where KeyID = ''[batchID]'' and m.Table_ID = ''Tax GL'' and m.Descr = ''9999999', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G63', '231', 'insert into TransX (KeyID, GL, TP, Contract, ReinName, TTY, Amt1) (Select KeyID,Descr as GL, TP, Contract, ReinName, Field2 as TTY, Amt1 * cast(Field3 as int) as Amt1 from TransX inner join Misc_Tables on GL = ID where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap7'' )', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-R25', '211', 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '601', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''1) RI'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G26'' and (GL = ''1099917'' or GL = ''2851017'' or substring(GL,1,4) in (''3572'',''3590'',''3591'',''3592'',''4398'')) and Flex5 = ''4) Other'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '602', 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G26'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''4) Other'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G26'' and (GL = ''1099917'' or GL = ''2851017'' or substring(GL,1,4) in (''3572'',''3590'',''3591'',''3592'',''4398'')) and Flex5 = ''4) Other'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '712', 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY = c.TTY and c.BC_From = '' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '713', 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY like c.TTY and c.BC_From = '' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '721', 'update TransX set  BusCat = '' where KeyID = ''[batchID]'' and not substring(GL,1,1) in (''4'',''5'') and not substring(GL,1,3) in (''283'',''284'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '722', 'update TransX set  BusCat = '' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''46'',''56'')', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-M25', '731', 'update t set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%', NULL, NULL, NULL, NULL, NULL, NULL),
    ('SQL-G27', '231', 'insert into TransX (KeyID, GL, PC, Amt3, Flex1) (Select ''[batchID]'' as KeyID, substring(GL,3,1), substring(PC,1,6), round(sum(Amt3),2) as Amt3, ''pass1'' from TransX where KeyID = ''[batchID]-data2'' group by substring(GL,3,1),substring(PC,1,6))', NULL, NULL, NULL, NULL, NULL, NULL),
